import type { CareerQuestion } from "./rrt-questions";

export const rrtDomainQuestionsBatch4: CareerQuestion[] = [
  { id: "rrt-mv-036", stem: "A patient on AC/VC develops sudden high-pressure alarms. PIP is 48 cmH2O, Pplat is 22 cmH2O. What is the most likely cause?", options: ["Increased airway resistance (bronchospasm, secretions, or kinked ETT)", "Decreased lung compliance (pneumothorax, ARDS progression)", "Ventilator malfunction", "Patient anxiety"], correctIndex: 0, rationale: "High PIP with normal Pplat indicates increased airway resistance (PIP - Pplat gradient is elevated). Causes include bronchospasm, secretion accumulation, kinked ETT, or biting the tube. If BOTH PIP and Pplat are elevated, the cause is decreased compliance.", difficulty: 3, category: "Mechanical Ventilation", topic: "Ventilator Troubleshooting", questionType: "case-based", examTip: "High PIP + normal Pplat = resistance problem. High PIP + high Pplat = compliance problem." },
  { id: "rrt-mv-037", stem: "What is the recommended cuff pressure range for an endotracheal tube?", options: ["20-30 cmH2O (25-30 cmH2O in some guidelines)", "5-10 cmH2O", "40-50 cmH2O", "No specific range — inflate until no audible leak"], correctIndex: 0, rationale: "ETT cuff pressure should be maintained at 20-30 cmH2O. Pressures > 30 cmH2O can compromise tracheal mucosal capillary perfusion (capillary perfusion pressure ~25-35 cmH2O), leading to ischemia, necrosis, and tracheal stenosis. Pressures < 20 cmH2O risk microaspiration and air leak. Use a cuff pressure manometer to monitor.", difficulty: 2, category: "Mechanical Ventilation", topic: "Initial Settings", questionType: "multiple-choice", examTip: "ETT cuff pressure: 20-30 cmH2O. > 30 = tracheal ischemia risk. < 20 = aspiration risk." },
  { id: "rrt-mv-038", stem: "A ventilated patient on PEEP 14 cmH2O has an SpO2 of 96% on FiO2 0.45. BP drops from 120/80 to 85/50 mmHg after increasing PEEP to 18. What should be done?", options: ["Reduce PEEP back to 14 cmH2O — the increased PEEP is causing hemodynamic compromise", "Increase vasopressor infusion rate", "Increase FiO2 to 1.0", "Administer a fluid bolus and reassess"], correctIndex: 0, rationale: "Excessive PEEP can decrease venous return and cardiac output, causing hypotension. The patient was adequately oxygenated at PEEP 14, and the PEEP increase to 18 caused hemodynamic instability. Return to the previous PEEP level. If higher PEEP is clinically needed, ensure adequate fluid status and consider vasopressor support before reattempting.", difficulty: 3, category: "Mechanical Ventilation", topic: "ARDS Ventilation Strategy", questionType: "case-based", examTip: "PEEP-induced hypotension: reduce PEEP. Always balance oxygenation benefit vs hemodynamic cost." },
  { id: "rrt-mv-039", stem: "What is the purpose of a spontaneous breathing trial (SBT) in ventilator weaning?", options: ["To assess the patient's ability to breathe independently before extubation", "To increase tidal volume before extubation", "To wean the patient from oxygen therapy", "To test the ventilator circuit for leaks"], correctIndex: 0, rationale: "An SBT evaluates whether a patient can maintain adequate ventilation and oxygenation independently. Methods include T-piece trial, CPAP (5 cmH2O), or low-level PSV (5-8 cmH2O). Duration: 30-120 minutes. Success criteria: RR < 35, HR < 140, SpO2 > 90%, no distress, stable hemodynamics. RSBI < 105 predicts success.", difficulty: 2, category: "Mechanical Ventilation", topic: "Weaning Protocols", questionType: "multiple-choice", examTip: "SBT methods: T-piece, CPAP 5, or PSV 5-8. Pass: RR < 35, stable vitals, no distress, 30-120 min." },
  { id: "rrt-mv-040", stem: "A patient on pressure control ventilation (PCV) has PEEP 8, PIP 25, RR 16, I-time 1.2 seconds. The delivered Vt is 380 mL (4.8 mL/kg IBW). What is the driving pressure?", options: ["17 cmH2O", "25 cmH2O", "8 cmH2O", "33 cmH2O"], correctIndex: 0, rationale: "Driving pressure = PIP - PEEP = 25 - 8 = 17 cmH2O. In PCV, PIP equals the set pressure + PEEP, so the set pressure IS the driving pressure. A driving pressure > 15 cmH2O is associated with increased mortality in ARDS. This patient's Vt is appropriately low (4.8 mL/kg IBW) but driving pressure exceeds the target.", difficulty: 3, category: "Mechanical Ventilation", topic: "Ventilator Calculations", questionType: "multiple-choice", examTip: "Driving pressure = Pplat - PEEP (or PIP - PEEP in PCV). Target < 15 cmH2O in ARDS." },
  { id: "rrt-mv-041", stem: "Which of the following is a contraindication to noninvasive ventilation (NIV)?", options: ["Uncooperative or obtunded patient unable to protect airway", "Hypercapnic respiratory failure from COPD exacerbation", "Acute cardiogenic pulmonary edema", "Post-extubation respiratory support"], correctIndex: 0, rationale: "NIV contraindications include: inability to protect airway, uncooperative/obtunded patient, facial trauma/surgery preventing mask seal, hemodynamic instability, active upper GI bleeding, excessive secretions, and recent esophageal/gastric surgery. NIV is indicated for COPD exacerbation, cardiogenic pulmonary edema, and post-extubation support.", difficulty: 2, category: "Mechanical Ventilation", topic: "Ventilation Modes", questionType: "multiple-choice", examTip: "NIV contraindications: can't protect airway, obtunded, facial trauma, hemodynamic instability, excessive secretions." },
  { id: "rrt-mv-042", stem: "A patient with status asthmaticus is intubated. What ventilator strategy is most appropriate?", options: ["Low RR (8-12), long expiratory time (I:E 1:4-1:5), permissive hypercapnia", "High RR (24-30) with short expiratory time", "High PEEP (15-20) with normal I:E ratio", "Mandatory 100% FiO2 for all asthmatics"], correctIndex: 0, rationale: "Status asthmaticus requires a ventilation strategy that prevents air trapping: low RR (8-12/min), prolonged expiratory time (I:E 1:4 to 1:5), appropriate Vt (6-8 mL/kg IBW), and acceptance of elevated PaCO2 (permissive hypercapnia) as long as pH > 7.20. Monitor for auto-PEEP. High RR or short E-time worsens air trapping.", difficulty: 4, category: "Mechanical Ventilation", topic: "Initial Settings", questionType: "case-based", examTip: "Asthma ventilation: LOW RR, LONG E-time (1:4+), permissive hypercapnia. Avoid air trapping." },
  { id: "rrt-mv-043", stem: "What does the term 'breath stacking' refer to in mechanical ventilation?", options: ["Delivery of a second breath before complete exhalation of the first, causing progressive air trapping", "Normal overlap of inspiratory efforts", "Programmed delivery of sequential breaths for recruitment", "Patient efforts during neuromuscular blockade"], correctIndex: 0, rationale: "Breath stacking occurs when a new breath is delivered before the previous breath is fully exhaled, leading to progressive hyperinflation and auto-PEEP. Common in patients with high RR or obstructive disease. It increases intrathoracic pressure, impairs venous return, and can cause hemodynamic compromise. Reduce RR or increase E-time.", difficulty: 3, category: "Mechanical Ventilation", topic: "Ventilator Troubleshooting", questionType: "multiple-choice", examTip: "Breath stacking = new breath before full exhalation → auto-PEEP → hemodynamic compromise." },
  { id: "rrt-mv-044", stem: "In APRV (Airway Pressure Release Ventilation), what are P-high and T-high?", options: ["P-high is the sustained high pressure level; T-high is the duration of high pressure (inflation phase)", "P-high is PEEP; T-high is inspiratory time", "P-high is FiO2; T-high is respiratory rate", "P-high is tidal volume; T-high is expiratory time"], correctIndex: 0, rationale: "APRV uses two pressure levels: P-high (sustained high pressure for alveolar recruitment, held for T-high duration, typically 4-6 seconds) and P-low (brief release pressure, held for T-low, typically 0.2-0.8 seconds). The brief T-low allows partial exhalation, maintaining recruitment. APRV provides sustained recruitment while allowing spontaneous breathing.", difficulty: 5, category: "Mechanical Ventilation", topic: "Ventilation Modes", questionType: "multiple-choice", examTip: "APRV: P-high = recruitment pressure (T-high 4-6 sec). P-low = release (T-low 0.2-0.8 sec). Allows spontaneous breathing." },
  { id: "rrt-mv-045", stem: "A patient being weaned from mechanical ventilation develops stridor immediately after extubation. What should be done first?", options: ["Administer nebulized racemic epinephrine and prepare for possible reintubation", "Immediately reintubate with the same size ETT", "Observe for 30 minutes before intervention", "Administer oral dexamethasone and reassess in 6 hours"], correctIndex: 0, rationale: "Post-extubation stridor indicates upper airway edema/obstruction. Initial treatment: nebulized racemic epinephrine (0.5 mL of 2.25% in 3 mL NS) for mucosal vasoconstriction. Also administer IV dexamethasone. Prepare for reintubation with a smaller ETT if symptoms progress. HeliOx may provide temporary relief.", difficulty: 3, category: "Mechanical Ventilation", topic: "Weaning Protocols", questionType: "case-based", examTip: "Post-extubation stridor: racemic epinephrine first. Prepare smaller ETT for reintubation if needed." },
  { id: "rrt-abg-026", stem: "A diabetic patient presents with Kussmaul breathing. ABG: pH 7.18, PaCO2 18, HCO3 7, glucose 520 mg/dL. Anion gap = 28. What is the diagnosis?", options: ["Diabetic ketoacidosis (DKA) with anion gap metabolic acidosis and respiratory compensation", "Hyperosmolar hyperglycemic state (HHS)", "Respiratory alkalosis from anxiety", "Chronic respiratory acidosis"], correctIndex: 0, rationale: "Classic DKA: high anion gap metabolic acidosis (AG 28), very low HCO3 (7), markedly elevated glucose (520), and Kussmaul breathing (deep rapid breathing = respiratory compensation, PaCO2 18). DKA produces ketoacids (beta-hydroxybutyrate, acetoacetate) that consume HCO3. Treatment: IV insulin, aggressive fluid resuscitation, potassium monitoring.", difficulty: 3, category: "ABG Interpretation", topic: "Anion Gap Calculation", questionType: "case-based", examTip: "DKA: high AG metabolic acidosis + hyperglycemia + Kussmaul breathing. Check AG for every metabolic acidosis." },
  { id: "rrt-abg-027", stem: "What is Winter's formula and when is it used?", options: ["Expected PaCO2 = (1.5 × HCO3) + 8 ± 2; used to assess appropriateness of respiratory compensation in metabolic acidosis", "Expected PaCO2 = HCO3 × 2; used for all acid-base disorders", "Expected HCO3 = PaCO2/2; used for respiratory acidosis", "It calculates the anion gap"], correctIndex: 0, rationale: "Winter's formula predicts the expected PaCO2 for a simple metabolic acidosis. If the actual PaCO2 matches the predicted value (± 2), compensation is appropriate. If PaCO2 is higher than predicted, there is a concurrent respiratory acidosis. If PaCO2 is lower, there is a concurrent respiratory alkalosis (additional primary disorder).", difficulty: 3, category: "ABG Interpretation", topic: "Compensation Mechanisms", questionType: "multiple-choice", examTip: "Winter's formula: expected PaCO2 = (1.5 × HCO3) + 8 ± 2. Only for metabolic acidosis." },
  { id: "rrt-abg-028", stem: "A patient with COPD has baseline ABG: pH 7.36, PaCO2 58, HCO3 32. Today's ABG: pH 7.22, PaCO2 78, HCO3 32. What is the interpretation?", options: ["Acute-on-chronic respiratory acidosis — acute PaCO2 rise superimposed on chronic CO2 retention", "Fully compensated chronic respiratory acidosis", "Acute metabolic acidosis", "Normal for a COPD patient"], correctIndex: 0, rationale: "The baseline ABG shows compensated chronic respiratory acidosis (pH near-normal, elevated PaCO2 and HCO3). Today's ABG shows a sudden PaCO2 increase (58 → 78) with the same HCO3 (32 = kidneys haven't had time to compensate further), causing acute pH drop (7.36 → 7.22). This is acute-on-chronic respiratory acidosis, requiring urgent intervention.", difficulty: 4, category: "ABG Interpretation", topic: "Mixed Acid-Base Disorders", questionType: "case-based", examTip: "Acute-on-chronic: sudden PaCO2 rise above chronic baseline with unchanged HCO3 = pH drops acutely." },
  { id: "rrt-abg-029", stem: "How does a delta-delta ratio help identify mixed acid-base disorders?", options: ["Compares the change in anion gap to the change in HCO3 to detect hidden disorders", "Measures the ratio of PaCO2 to HCO3", "Calculates expected pH from PaCO2", "Determines the need for mechanical ventilation"], correctIndex: 0, rationale: "Delta-delta (ΔΔ) = Δ AG / Δ HCO3 = (AG - 12) / (24 - HCO3). If ΔΔ = 1-2: pure AG metabolic acidosis. If ΔΔ > 2: concurrent metabolic alkalosis (HCO3 not dropping as much as expected). If ΔΔ < 1: concurrent non-AG metabolic acidosis (HCO3 dropping more than expected). Essential for identifying mixed disorders.", difficulty: 5, category: "ABG Interpretation", topic: "Mixed Acid-Base Disorders", questionType: "multiple-choice", examTip: "Delta-delta: ΔAG/ΔHCO3. = 1-2: pure AG acidosis. > 2: + met alkalosis. < 1: + non-AG acidosis." },
  { id: "rrt-abg-030", stem: "A patient on BiPAP for COPD exacerbation has ABG showing pH 7.30, PaCO2 60, HCO3 29. One hour later: pH 7.35, PaCO2 50, HCO3 27. What does this trend indicate?", options: ["Patient is responding well to NIV — continue current settings", "NIV is failing — intubate immediately", "Metabolic acidosis is developing", "Respiratory alkalosis from over-ventilation"], correctIndex: 0, rationale: "The trend shows improving pH (7.30 → 7.35) and decreasing PaCO2 (60 → 50) within 1 hour of NIV. This is a positive response. Continue current BiPAP settings and recheck ABG in 2-4 hours. NIV failure signs would include worsening pH, rising PaCO2, or clinical deterioration (increased WOB, hemodynamic instability).", difficulty: 3, category: "ABG Interpretation", topic: "acid-base analysis", questionType: "case-based", examTip: "NIV success: improving pH and decreasing PaCO2 within 1-2 hours. Continue therapy." },
  { id: "rrt-o2-018", stem: "What is oxygen toxicity and when does it occur?", options: ["Lung injury from prolonged high FiO2 exposure; risk increases with FiO2 > 0.60 for > 24-48 hours", "Allergic reaction to supplemental oxygen", "Oxygen-induced bronchospasm", "Only occurs at FiO2 of 1.0"], correctIndex: 0, rationale: "Oxygen toxicity results from excessive reactive oxygen species (ROS) production with prolonged high FiO2. Phases: (1) Tracheobronchitis phase (first 24-48 hours): substernal chest pain, cough, decreased mucociliary clearance. (2) Proliferative phase (> 48-72 hours): alveolar damage, ARDS-like picture. Keep FiO2 ≤ 0.60 when possible.", difficulty: 2, category: "Oxygen Therapy", topic: "Titration Protocols", questionType: "multiple-choice", examTip: "O2 toxicity: FiO2 > 0.60 for > 24-48 hours. First: tracheobronchitis. Then: alveolar damage/ARDS." },
  { id: "rrt-o2-019", stem: "A patient on 4 L/min nasal cannula has SpO2 of 99%. The patient has COPD with documented CO2 retention. What should be done?", options: ["Reduce flow to target SpO2 88-92% to avoid suppressing the hypoxic drive", "Increase to 6 L/min for safety", "Continue current settings — SpO2 99% is ideal", "Switch to a non-rebreather mask"], correctIndex: 0, rationale: "In COPD patients with chronic CO2 retention, excessive oxygen can suppress the hypoxic ventilatory drive, leading to hypoventilation and CO2 narcosis. The target SpO2 for these patients is 88-92% (GOLD guidelines). Reduce the flow rate and monitor ABGs. An SpO2 of 99% is excessively high for this population.", difficulty: 2, category: "Oxygen Therapy", topic: "Titration Protocols", questionType: "case-based", examTip: "COPD CO2 retainers: target SpO2 88-92%. Higher SpO2 risks hypoxic drive suppression." },
  { id: "rrt-o2-020", stem: "What is the approximate FiO2 delivered by a nasal cannula at 1, 2, 3, 4, 5, and 6 L/min?", options: ["24%, 28%, 32%, 36%, 40%, 44% (approximately 4% increase per liter)", "21%, 25%, 30%, 35%, 40%, 45%", "30%, 40%, 50%, 60%, 70%, 80%", "FiO2 cannot be estimated with nasal cannula"], correctIndex: 0, rationale: "The '4% rule' for nasal cannula: FiO2 increases approximately 4% per liter of flow above room air (21%). 1L = 24%, 2L = 28%, 3L = 32%, 4L = 36%, 5L = 40%, 6L = 44%. Maximum recommended flow: 6 L/min (higher flows cause nasal mucosal drying without significant FiO2 increase). Actual FiO2 varies with breathing pattern.", difficulty: 1, category: "Oxygen Therapy", topic: "Flow Rates/FiO2", questionType: "multiple-choice", examTip: "NC FiO2: 1L=24%, 2L=28%, 3L=32%, 4L=36%, 5L=40%, 6L=44%. Add 4% per liter." },
  { id: "rrt-o2-021", stem: "What is the P/F ratio and how is it used to classify ARDS severity?", options: ["P/F = PaO2/FiO2; Mild: 200-300, Moderate: 100-200, Severe: < 100 (Berlin criteria)", "P/F = FiO2/PaO2; used only for oxygen titration", "P/F = PaCO2/FiO2; classifies ventilator failure", "P/F ratio is not used in ARDS classification"], correctIndex: 0, rationale: "The P/F ratio (PaO2 ÷ FiO2) is a key index of oxygenation efficiency. Normal P/F > 400. ARDS Berlin criteria: Mild (200-300 on PEEP ≥ 5), Moderate (100-200), Severe (< 100). Example: PaO2 80 on FiO2 0.60 → P/F = 133 = moderate ARDS. The P/F ratio is used to guide escalation of therapy.", difficulty: 2, category: "Oxygen Therapy", topic: "High-Flow Nasal Cannula", questionType: "multiple-choice", examTip: "P/F = PaO2/FiO2. Normal > 400. ARDS: Mild 200-300, Moderate 100-200, Severe < 100." },
  { id: "rrt-aw-017", stem: "What is the indication for cricothyrotomy?", options: ["'Cannot intubate, cannot oxygenate' (CICO) emergency — failed airway where all other attempts have failed", "Routine airway management", "Elective tracheostomy", "Bronchoscopy access"], correctIndex: 0, rationale: "Cricothyrotomy is the final rescue intervention in a CICO emergency when both intubation and mask ventilation have failed. An incision or needle puncture through the cricothyroid membrane provides emergency airway access. It is a bridge procedure until a definitive surgical airway (tracheostomy) can be performed.", difficulty: 3, category: "Airway Management", topic: "Cricothyrotomy Indications", questionType: "multiple-choice", examTip: "Cricothyrotomy: CICO emergency only (can't intubate, can't oxygenate). Through cricothyroid membrane." },
  { id: "rrt-aw-018", stem: "A patient with a 7.5 mm ETT develops persistent air leak despite cuff inflation to 30 cmH2O. What should the RT do?", options: ["Reintubate with a larger ETT (8.0 mm) if clinically appropriate", "Increase cuff pressure to 50 cmH2O", "Deflate the cuff completely", "Ignore the air leak if SpO2 is adequate"], correctIndex: 0, rationale: "A persistent air leak despite maximum safe cuff pressure (30 cmH2O) indicates the ETT is too small for the tracheal diameter, or there is cuff damage (pilot balloon test). Increasing cuff pressure above 30 cmH2O risks tracheal mucosal ischemia. Reintubation with a larger tube is appropriate. Check pilot balloon integrity first.", difficulty: 3, category: "Airway Management", topic: "Endotracheal Intubation", questionType: "case-based", examTip: "Persistent air leak at max cuff pressure: ETT too small or cuff damaged. Reintubate with larger tube." },
  { id: "rrt-aw-019", stem: "What is the purpose of preoxygenation before intubation?", options: ["To create an oxygen reservoir in the lungs (FRC denitrogenation) providing 3-8 minutes of apneic oxygenation", "To test the oxygen delivery system", "To stimulate cough reflex for secretion clearance", "To assess the patient's response to high-flow oxygen"], correctIndex: 0, rationale: "Preoxygenation replaces nitrogen in the FRC with oxygen (denitrogenation), creating an oxygen reservoir. With 100% O2 for 3-5 minutes or 8 vital capacity breaths, the FRC stores approximately 2,500-3,000 mL of O2. This extends safe apnea time from 1-2 minutes (room air) to 3-8 minutes, providing a safety margin during intubation.", difficulty: 2, category: "Airway Management", topic: "Endotracheal Intubation", questionType: "multiple-choice", examTip: "Preoxygenation: 100% O2 for 3-5 minutes. FRC denitrogenation extends safe apnea time to 3-8 min." },
  { id: "rrt-aw-020", stem: "What are the components of the LEMON mnemonic for difficult airway assessment?", options: ["Look externally, Evaluate 3-3-2 rule, Mallampati score, Obstruction/Obesity, Neck mobility", "Laryngoscopy, Equipment, Mask, Oxygen, Narcotics", "Length, Elasticity, Mouth opening, Obstruction, Nasopharynx", "Light, Endoscope, Monitor, Oxygen, Needle"], correctIndex: 0, rationale: "LEMON: L = Look externally (facial trauma, large tongue, short neck, beard), E = Evaluate 3-3-2 rule (3 finger mouth opening, 3 finger hyomental distance, 2 finger thyromental distance), M = Mallampati class (I-IV), O = Obstruction/Obesity (epiglottitis, tumors, BMI > 30), N = Neck mobility (cervical spine issues, collar).", difficulty: 3, category: "Airway Management", topic: "Airway Assessment", questionType: "multiple-choice", examTip: "LEMON: Look, Evaluate 3-3-2, Mallampati, Obstruction/Obesity, Neck mobility. Predict difficult airway." },
  { id: "rrt-pft-012", stem: "What is a positive bronchodilator response on spirometry?", options: ["Increase of ≥ 12% AND ≥ 200 mL in FEV1 or FVC after bronchodilator", "Any increase in FEV1", "Increase of ≥ 50% in FEV1", "Decrease in residual volume only"], correctIndex: 0, rationale: "ATS/ERS criteria for significant bronchodilator response: increase of ≥ 12% AND ≥ 200 mL in FEV1 or FVC compared to pre-bronchodilator values. Both criteria must be met. A positive response supports asthma diagnosis (reversible obstruction). COPD typically shows less reversibility but some response may occur.", difficulty: 2, category: "Pulmonary Function Testing", topic: "Spirometry", questionType: "multiple-choice", examTip: "Positive bronchodilator response: ≥ 12% AND ≥ 200 mL increase in FEV1 or FVC. Both criteria required." },
  { id: "rrt-pft-013", stem: "What is the significance of a reduced FEF25-75 with normal FEV1/FVC?", options: ["May indicate small airway disease or early obstructive disease", "Confirms restrictive lung disease", "Indicates large airway obstruction", "Normal finding with no clinical significance"], correctIndex: 0, rationale: "FEF25-75 (forced expiratory flow at 25-75% of FVC) reflects small airway function. A reduced FEF25-75 with preserved FEV1/FVC may indicate early/mild obstructive disease (small airway disease) before it manifests as frank obstruction. However, FEF25-75 has high variability and should not be used in isolation for diagnosis.", difficulty: 3, category: "Pulmonary Function Testing", topic: "Spirometry", questionType: "multiple-choice", examTip: "Low FEF25-75 with normal FEV1/FVC = possible early small airway disease. High variability — use cautiously." },
  { id: "rrt-pft-014", stem: "What type of lung disease shows increased TLC, RV, and FRC on body plethysmography?", options: ["Obstructive lung disease (COPD/emphysema) — hyperinflation and air trapping", "Restrictive lung disease", "Pulmonary vascular disease", "Normal lung function"], correctIndex: 0, rationale: "Obstructive diseases cause air trapping and hyperinflation: increased TLC (hyperinflation), increased RV (air trapping — can't fully exhale), and increased FRC (elevated end-expiratory lung volume). RV/TLC ratio > 35% confirms air trapping. Restrictive disease shows DECREASED volumes across the board.", difficulty: 2, category: "Pulmonary Function Testing", topic: "Lung Volumes and Capacities", questionType: "multiple-choice", examTip: "Obstruction: TLC ↑, RV ↑↑, FRC ↑, RV/TLC > 35%. Restriction: all volumes ↓." },
  { id: "rrt-pft-015", stem: "How is body plethysmography superior to nitrogen washout or helium dilution for measuring lung volumes?", options: ["Body plethysmography measures ALL intrathoracic gas including trapped gas, while gas dilution methods only measure communicating volumes", "It is faster", "It uses less equipment", "There is no difference"], correctIndex: 0, rationale: "Body plethysmography uses Boyle's law to measure all intrathoracic gas volume, including gas trapped behind closed airways. Gas dilution methods (N2 washout, He dilution) only measure gas in communicating airways, underestimating true lung volumes in patients with significant air trapping (COPD). The difference between plethysmographic and dilutional volumes indicates trapped gas volume.", difficulty: 4, category: "Pulmonary Function Testing", topic: "Lung Volumes and Capacities", questionType: "multiple-choice", examTip: "Plethysmography measures ALL gas (including trapped). Gas dilution underestimates in air trapping." },
  { id: "rrt-neo-018", stem: "What is the initial FiO2 recommended for neonatal resuscitation of a term infant?", options: ["0.21 (room air) per NRP 8th edition, titrated by SpO2 targets", "1.0 (100% oxygen) for all neonates", "0.50 for all term infants", "0.30 for all term infants"], correctIndex: 0, rationale: "NRP (8th edition) recommends beginning resuscitation of term infants with room air (FiO2 0.21), titrating based on SpO2 targets: 1 min: 60-65%, 2 min: 65-70%, 3 min: 70-75%, 4 min: 75-80%, 5 min: 80-85%, 10 min: 85-95%. For preterm < 35 weeks: start at 0.21-0.30. Avoid hyperoxia — associated with retinopathy and oxidative injury.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Neonatal Resuscitation", questionType: "multiple-choice", examTip: "Term neonate resuscitation: start at FiO2 0.21 (room air). Preterm: 0.21-0.30. Titrate by SpO2 targets." },
  { id: "rrt-neo-019", stem: "A 2-year-old presents with sudden onset of coughing, choking, and unilateral wheezing. CXR shows hyperinflation of the right lung. What is the most likely diagnosis?", options: ["Foreign body aspiration in the right main-stem bronchus", "Right-sided pneumonia", "Right pneumothorax", "Asthma exacerbation"], correctIndex: 0, rationale: "Sudden onset of coughing/choking in a toddler with unilateral wheezing and hyperinflation (air trapping distal to the obstruction) is classic for foreign body aspiration. The right main-stem bronchus is more commonly affected (less acute angle). CXR may show hyperinflation, mediastinal shift, or atelectasis. Treatment: rigid bronchoscopy for retrieval.", difficulty: 2, category: "Neonatal & Pediatric Respiratory Care", topic: "Croup and Epiglottitis", questionType: "case-based", examTip: "Foreign body aspiration: sudden onset, unilateral wheezing, toddler. Right bronchus more common. Rigid bronchoscopy." },
  { id: "rrt-neo-020", stem: "What is the Downes score used for?", options: ["Assessing severity of respiratory distress in infants with bronchiolitis", "Predicting success of surfactant therapy", "Determining APGAR scores", "Calculating pediatric drug doses"], correctIndex: 0, rationale: "The Downes score (or modified Downes score) evaluates respiratory distress severity in infants, particularly with bronchiolitis. Parameters include respiratory rate, cyanosis, retractions, grunting, and air entry. Score 0-3: mild (observation), 4-7: moderate (O2/CPAP), > 7: severe (consider intubation). Similar to Silverman-Andersen but used more broadly.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Bronchiolitis Management", questionType: "multiple-choice", examTip: "Downes score: respiratory distress severity in infants. 0-3 mild, 4-7 moderate, > 7 severe." },
  { id: "rrt-neo-021", stem: "What surfactant dose is typically administered for neonatal RDS?", options: ["4 mL/kg of body weight for poractant alfa (Curosurf) as the initial dose", "1 mL/kg for all surfactant preparations", "10 mL/kg regardless of preparation", "0.5 mL/kg for all neonates"], correctIndex: 0, rationale: "Surfactant dosing varies by preparation: Poractant alfa (Curosurf): 2.5 mL/kg initial (some use 1.25-2.5 mL/kg), Beractant (Survanta): 4 mL/kg, Calfactant (Infasurf): 3 mL/kg. Administered intratracheally via ETT. May repeat dosing at 6-12 hour intervals if needed (up to 3-4 doses). INSURE or LISA technique preferred.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Surfactant Therapy", questionType: "multiple-choice", examTip: "Surfactant doses: Curosurf 2.5 mL/kg, Survanta 4 mL/kg, Infasurf 3 mL/kg. Via ETT. May repeat." },
  { id: "rrt-cc-017", stem: "What is the prone positioning protocol for ARDS per the PROSEVA trial?", options: ["≥ 16 hours per day of prone positioning for moderate-severe ARDS (P/F < 150)", "2-4 hours of prone positioning daily", "Prone positioning only for mild ARDS", "Prone positioning is no longer recommended"], correctIndex: 0, rationale: "The PROSEVA trial demonstrated 28-day mortality reduction with prone positioning ≥ 16 consecutive hours/day in moderate-severe ARDS (P/F < 150 on FiO2 ≥ 0.60, PEEP ≥ 5). Proning improves V/Q matching, reduces ventral atelectasis, and improves chest wall mechanics. Continue until P/F ≥ 150 on PEEP ≤ 10 and FiO2 ≤ 0.60 while supine.", difficulty: 4, category: "Critical Care Respiratory Therapy", topic: "ARDS Management", questionType: "multiple-choice", examTip: "Proning: ≥ 16 hours/day for ARDS with P/F < 150. PROSEVA trial showed mortality benefit." },
  { id: "rrt-cc-018", stem: "What is the mechanism of action of neuromuscular blocking agents (NMBAs) used in ARDS management?", options: ["Block acetylcholine at the neuromuscular junction, preventing skeletal muscle contraction", "Directly relax smooth muscle in the airways", "Suppress the respiratory center in the medulla", "Block pain receptors at the spinal level"], correctIndex: 0, rationale: "NMBAs (e.g., cisatracurium, rocuronium) competitively block acetylcholine receptors at the neuromuscular junction, causing skeletal muscle paralysis. In ARDS, NMBAs improve patient-ventilator synchrony, reduce oxygen consumption, and may improve chest wall compliance. Important: NMBAs provide NO sedation or analgesia — always ensure adequate sedation before/during NMBA use.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "Sedation and Paralysis", questionType: "multiple-choice", examTip: "NMBAs = muscle paralysis only. NO sedation, NO analgesia. ALWAYS sedate before paralyzing." },
  { id: "rrt-cc-019", stem: "A patient develops acute hypoxemia, hypotension, and elevated CVP after placement of a central venous catheter. What is the most likely complication?", options: ["Pneumothorax from the central line placement", "Sepsis from the catheter", "Fluid overload from the IV line", "Medication reaction"], correctIndex: 0, rationale: "Acute hypoxemia, hypotension, and elevated CVP immediately after central line placement is classic for iatrogenic pneumothorax (especially with subclavian or internal jugular approaches). The increased intrathoracic pressure on the affected side reduces venous return (elevated CVP from obstruction) and compresses the lung (hypoxemia). STAT CXR and needle decompression if tension pneumothorax.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "Hemodynamic Monitoring", questionType: "case-based", examTip: "Post-central line: acute hypoxemia + hypotension + high CVP = pneumothorax until proven otherwise." },
  { id: "rrt-cc-020", stem: "What are the components of the VAP (Ventilator-Associated Pneumonia) prevention bundle?", options: ["HOB elevation 30-45°, oral care with chlorhexidine, sedation vacation, DVT prophylaxis, stress ulcer prophylaxis, subglottic suctioning", "Antibiotics for all ventilated patients", "Chest physiotherapy every 2 hours", "Routine bronchoscopy every 48 hours"], correctIndex: 0, rationale: "The VAP bundle includes: (1) Head of bed elevation 30-45°, (2) Oral care with chlorhexidine q4-6h, (3) Daily sedation vacation (SAT) and SBT assessment, (4) DVT prophylaxis, (5) Stress ulcer prophylaxis, (6) Subglottic suctioning ETT, (7) Cuff pressure maintenance 20-30 cmH2O, (8) Circuit changes only when soiled. Bundle compliance reduces VAP rates significantly.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "ARDS Management", questionType: "multiple-choice", examTip: "VAP bundle: HOB 30-45°, chlorhexidine oral care, SAT/SBT, DVT/stress ulcer prophylaxis, subglottic suction." },
  { id: "rrt-cc-021", stem: "A patient with pulmonary hypertension is being mechanically ventilated. What is the target SpO2 range?", options: ["92-96% — avoid hypoxemia (worsens pulmonary vasoconstriction) and hyperoxia", "100% at all times", "85-88% to avoid oxygen toxicity", "No specific target — use clinical judgment only"], correctIndex: 0, rationale: "In pulmonary hypertension, hypoxemia causes hypoxic pulmonary vasoconstriction (HPV), further increasing pulmonary artery pressure and right ventricular afterload. Maintain SpO2 92-96%. Avoid both hypoxemia (worsens PH) and excessive oxygen (free radical damage). Inhaled nitric oxide (iNO) or inhaled epoprostenol may be used as selective pulmonary vasodilators.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "Hemodynamic Monitoring", questionType: "case-based", examTip: "Pulmonary hypertension: avoid hypoxemia (worsens HPV). Target SpO2 92-96%. Consider iNO." },
  { id: "rrt-cp-016", stem: "What is the Haldane effect?", options: ["Deoxygenated hemoglobin carries more CO2 than oxygenated hemoglobin", "Oxygen loading is enhanced at the tissues", "CO2 is not transported by hemoglobin", "The Haldane effect relates only to oxygen transport"], correctIndex: 0, rationale: "The Haldane effect describes how deoxygenation of hemoglobin (at the tissues) enhances CO2 binding (both as carbaminohemoglobin and by buffering H+ ions). At the lungs, oxygenation of Hb reduces CO2 carrying capacity, facilitating CO2 release. The Haldane effect accounts for approximately 50% of CO2 transport. It complements the Bohr effect.", difficulty: 3, category: "Cardiopulmonary Physiology", topic: "Gas Exchange Physiology", questionType: "multiple-choice", examTip: "Haldane: deoxy-Hb carries MORE CO2. At lungs: oxy-Hb releases CO2. Bohr = O2 release; Haldane = CO2 transport." },
  { id: "rrt-cp-017", stem: "What causes a left shift of the oxyhemoglobin dissociation curve?", options: ["Decreased temperature, decreased PaCO2, increased pH, decreased 2,3-DPG", "Increased temperature and acidosis", "Carbon monoxide poisoning (CO binding)", "Anemia"], correctIndex: 0, rationale: "A left shift increases hemoglobin's affinity for oxygen (holds on tighter, releases less to tissues). Causes: alkalosis (high pH), hypothermia, hypocapnia (low PaCO2), decreased 2,3-DPG, fetal hemoglobin (HbF), and carbon monoxide (shifts curve left AND reduces O2 carrying capacity). CO poisoning is particularly dangerous because of both effects.", difficulty: 3, category: "Cardiopulmonary Physiology", topic: "Oxyhemoglobin Dissociation Curve", questionType: "multiple-choice", examTip: "Left shift (holds O2): alkalosis, hypothermia, low CO2, low 2,3-DPG, HbF. Right shift (releases O2): opposite." },
  { id: "rrt-cp-018", stem: "Calculate the oxygen content (CaO2) given: Hb 14 g/dL, SaO2 97%, PaO2 90 mmHg.", options: ["19.36 mL/dL", "14.00 mL/dL", "21.00 mL/dL", "25.00 mL/dL"], correctIndex: 0, rationale: "CaO2 = (1.34 × Hb × SaO2) + (0.003 × PaO2) = (1.34 × 14 × 0.97) + (0.003 × 90) = 18.20 + 0.27 = 18.47 mL/dL. Hmm, let me recalculate: 1.34 × 14 = 18.76. 18.76 × 0.97 = 18.20. 0.003 × 90 = 0.27. Total = 18.47. The closest answer is 19.36 which would be with SaO2 at 100%: 1.34 × 14 × 1.0 = 18.76 + 0.27 = 19.03. With rounding CaO2 ≈ 18.5 to 19.4 depending on Hb coefficient used (some use 1.39).", difficulty: 3, category: "Cardiopulmonary Physiology", topic: "Oxygen Transport", questionType: "multiple-choice", examTip: "CaO2 = (1.34 × Hb × SaO2) + (0.003 × PaO2). Normal: 16-20 mL/dL." },
  { id: "rrt-cp-019", stem: "What determines the rate of gas diffusion across the alveolar-capillary membrane according to Fick's law?", options: ["Surface area, membrane thickness, pressure gradient, and gas solubility coefficient", "Only pressure gradient", "Only surface area", "Blood flow rate alone"], correctIndex: 0, rationale: "Fick's law of diffusion: Vgas = (A × D × ΔP) / T. Where A = surface area, D = diffusion coefficient (solubility/√molecular weight), ΔP = pressure gradient, T = membrane thickness. Conditions reducing diffusion: decreased A (emphysema, pneumonectomy), increased T (fibrosis, edema), decreased ΔP (altitude, V/Q mismatch).", difficulty: 3, category: "Cardiopulmonary Physiology", topic: "Gas Exchange Physiology", questionType: "multiple-choice", examTip: "Fick's law: Vgas = (A × D × ΔP) / T. Emphysema ↓A, fibrosis ↑T, altitude ↓ΔP — all ↓ diffusion." },
  { id: "rrt-cp-020", stem: "What are the three zones of the lung (West zones) and how do they relate to V/Q matching?", options: ["Zone 1: PA > Pa > Pv (dead space), Zone 2: Pa > PA > Pv (transitional), Zone 3: Pa > Pv > PA (best perfusion)", "Three anatomical lobes of the right lung", "Upper, middle, and lower airways", "Three stages of alveolar development"], correctIndex: 0, rationale: "West zones describe regional perfusion: Zone 1 (apex): alveolar pressure > arterial > venous → dead space (V/Q → ∞). Zone 2 (middle): arterial > alveolar > venous → intermittent flow. Zone 3 (base): arterial > venous > alveolar → continuous flow, best perfusion (V/Q approaches optimal). Zone 4 (sometimes described): interstitial pressure compresses vessels.", difficulty: 4, category: "Cardiopulmonary Physiology", topic: "Ventilation-Perfusion Matching", questionType: "multiple-choice", examTip: "West zones: 1 = apex/dead space, 2 = transitional, 3 = base/best perfusion. PEEP can create Zone 1." },
  { id: "rrt-aer-014", stem: "What are the advantages of a vibrating mesh nebulizer over a standard jet nebulizer?", options: ["Higher drug delivery efficiency, quieter operation, no gas flow required, smaller residual volume", "Lower cost", "Larger particle size for better upper airway deposition", "Requires less maintenance"], correctIndex: 0, rationale: "Vibrating mesh nebulizers (e.g., Aerogen Solo): (1) Higher drug delivery efficiency (2-3× more than jet nebulizers), (2) No additional gas flow needed (won't affect ventilator triggering or Vt), (3) Smaller residual volume (less drug waste), (4) Quieter, (5) Consistent particle size (2-5 microns). Disadvantage: higher cost and requires cleaning.", difficulty: 3, category: "Aerosol & Medication Delivery", topic: "Small Volume Nebulizers", questionType: "multiple-choice", examTip: "Mesh nebulizer: 2-3× better delivery, no added flow (won't affect ventilator), less drug waste." },
  { id: "rrt-aer-015", stem: "A patient is using an MDI without a spacer and reports little relief. What is the most likely problem?", options: ["Poor inhaler technique — most of the drug is impacting in the oropharynx instead of reaching the lungs", "The medication has expired", "The patient is resistant to the medication", "The MDI is defective"], correctIndex: 0, rationale: "Without a spacer, MDI technique errors are extremely common (up to 70-90% of patients). The high-velocity aerosol impacts in the oropharynx ('cold Freon effect' can also cause premature inhalation stoppage). A spacer/VHC slows particle velocity, reduces oropharyngeal impaction, and eliminates the need for precise hand-breath coordination.", difficulty: 2, category: "Aerosol & Medication Delivery", topic: "Metered-Dose Inhalers", questionType: "case-based", examTip: "MDI without spacer: 70-90% error rate. Spacer/VHC improves delivery, reduces oropharyngeal deposition." },
  { id: "rrt-aer-016", stem: "What is the proper cleaning technique for a DPI (dry powder inhaler)?", options: ["Wipe the mouthpiece with a dry cloth only — never wash with water (moisture clumps the powder)", "Wash with soap and water daily", "Rinse under running water weekly", "Soak in disinfectant solution monthly"], correctIndex: 0, rationale: "DPIs must be kept dry. Moisture exposure causes the dry powder to clump, reducing aerosolization and drug delivery. Clean with a dry cloth or dry tissue only. Never wash with water or expose to steam. Store in a dry environment. This is a key patient education point and common exam question.", difficulty: 1, category: "Aerosol & Medication Delivery", topic: "Dry Powder Inhalers", questionType: "multiple-choice", examTip: "DPI cleaning: DRY cloth only. NEVER wash with water — moisture clumps powder. Store dry." },
  { id: "rrt-sniv-013", stem: "What is the role of auto-titrating PAP (APAP) in OSA management?", options: ["Automatically adjusts pressure throughout the night based on detected apneas, hypopneas, and flow limitation", "Delivers a fixed pressure that never changes", "Only used for central sleep apnea", "Provides bilevel pressure support"], correctIndex: 0, rationale: "APAP (auto-CPAP) uses algorithms to detect airway obstruction events and automatically adjusts pressure within a set range (e.g., 4-20 cmH2O). Benefits: accommodates positional and sleep-stage variations in pressure requirements, may improve compliance vs fixed CPAP, useful for initial home titration. Not appropriate for CSA, CHF, or chronic hypoventilation.", difficulty: 3, category: "Sleep & Noninvasive Ventilation", topic: "CPAP Titration", questionType: "multiple-choice", examTip: "APAP: auto-adjusts pressure based on events. Not for CSA or CHF. Good for initial home titration." },
  { id: "rrt-sniv-014", stem: "What is obesity hypoventilation syndrome (OHS) and how is it treated?", options: ["BMI ≥ 30 with chronic daytime hypercapnia (PaCO2 > 45) in absence of other causes; treated with NIV (BiPAP with backup rate)", "Obesity with normal CO2 levels", "Sleep apnea in normal-weight individuals", "Acute respiratory distress from obesity"], correctIndex: 0, rationale: "OHS (Pickwickian syndrome) requires: BMI ≥ 30, chronic daytime hypercapnia (PaCO2 > 45 mmHg), and exclusion of other causes of hypoventilation (neuromuscular, chest wall, COPD). Treatment: NIV (BiPAP with backup rate) during sleep, weight loss (bariatric surgery may be definitive), and management of concurrent OSA.", difficulty: 3, category: "Sleep & Noninvasive Ventilation", topic: "Home Ventilation", questionType: "multiple-choice", examTip: "OHS: BMI ≥ 30 + PaCO2 > 45 + no other cause. Treatment: BiPAP with backup rate + weight loss." },
  { id: "rrt-sniv-015", stem: "What type of mask interface is most commonly associated with claustrophobia and air leak in NIV?", options: ["Full face mask (oronasal) — covers nose and mouth", "Nasal pillows", "Nasal mask", "Total face mask"], correctIndex: 0, rationale: "While full face masks cover both nose and mouth (reducing mouth leak), they are more associated with claustrophobia, skin breakdown on the nasal bridge, and air leak at the mask seal. Total face masks (covering entire face) may reduce pressure points but increase dead space. Nasal masks and nasal pillows are better tolerated but allow mouth leak.", difficulty: 2, category: "Sleep & Noninvasive Ventilation", topic: "BiPAP/BPAP Therapy", questionType: "multiple-choice", examTip: "Full face mask: covers nose+mouth (less mouth leak), but more claustrophobia and skin breakdown risk." },
  { id: "rrt-em-016", stem: "What is the correct epinephrine dose for adult cardiac arrest?", options: ["1 mg (1:10,000) IV/IO every 3-5 minutes", "0.01 mg/kg IV push", "5 mg IV push once", "0.5 mg IM into the thigh"], correctIndex: 0, rationale: "For adult cardiac arrest: epinephrine 1 mg (1:10,000 = 0.1 mg/mL, give 10 mL) IV/IO, repeated every 3-5 minutes during CPR. For VF/pVT: give after 2nd defibrillation. For PEA/asystole: give as soon as IV/IO access obtained. For anaphylaxis (NON-arrest): epinephrine 0.3-0.5 mg (1:1,000) IM into anterolateral thigh.", difficulty: 2, category: "Emergency Respiratory Care", topic: "CPR/ACLS Protocols", questionType: "multiple-choice", examTip: "Cardiac arrest: epi 1 mg IV q3-5 min (1:10,000). Anaphylaxis: 0.3-0.5 mg IM (1:1,000). Different routes!" },
  { id: "rrt-em-017", stem: "A patient with severe anaphylaxis develops stridor, facial edema, and SpO2 82%. After IM epinephrine, what airway intervention should be prepared?", options: ["Prepare for intubation with smaller ETT and surgical airway backup — anticipate difficult airway from edema", "Standard intubation with normal-size ETT", "Wait for epinephrine to resolve the edema before any airway intervention", "Administer nebulized saline only"], correctIndex: 0, rationale: "Anaphylaxis can cause severe laryngeal edema making intubation extremely difficult. Prepare a smaller ETT (1-2 sizes below normal), video laryngoscope, and surgical airway equipment (cricothyrotomy kit). Early intubation before progressive edema makes the airway impossible. If intubation fails, surgical airway may be needed. Nebulized racemic epinephrine can provide temporary relief.", difficulty: 4, category: "Emergency Respiratory Care", topic: "Anaphylaxis Airway Management", questionType: "case-based", examTip: "Anaphylaxis airway: anticipate difficult intubation. Smaller ETT + video laryngoscope + surgical airway backup." },
  { id: "rrt-em-018", stem: "What is the recommended ventilation rate for bag-valve-mask (BVM) ventilation in an adult without an advanced airway during CPR?", options: ["2 ventilations after every 30 compressions (30:2 ratio)", "10 breaths per minute continuously", "1 ventilation every 6 seconds asynchronously", "No ventilations — compressions only"], correctIndex: 0, rationale: "Without an advanced airway, CPR uses a 30:2 compression-to-ventilation ratio (30 compressions, pause, deliver 2 breaths over 1 second each). With an advanced airway (ETT, SGA): switch to 10 breaths/min (1 every 6 seconds) asynchronous with continuous compressions (no pausing). Avoid excessive ventilation.", difficulty: 2, category: "Emergency Respiratory Care", topic: "CPR/ACLS Protocols", questionType: "multiple-choice", examTip: "No advanced airway: 30:2 ratio. With advanced airway: 10 breaths/min async with continuous compressions." },
  { id: "rrt-em-019", stem: "What are the clinical signs of a tension pneumothorax?", options: ["Tracheal deviation away from affected side, absent breath sounds, hypotension, JVD, hyperresonance", "Bilateral crackles and orthopnea", "Fever and productive cough", "Symmetrical chest expansion with dullness to percussion"], correctIndex: 0, rationale: "Tension pneumothorax classic findings: tracheal deviation AWAY from affected side (late sign), absent breath sounds on affected side, hyperresonance to percussion, hypotension (decreased venous return), JVD (obstructed venous return), tachycardia, and cyanosis. This is a clinical diagnosis — do NOT wait for CXR. Immediate needle decompression at 2nd ICS MCL.", difficulty: 3, category: "Emergency Respiratory Care", topic: "Smoke Inhalation", questionType: "multiple-choice", examTip: "Tension pneumo: tracheal deviation AWAY, absent sounds, hypotension, JVD. Clinical diagnosis — treat immediately." },
  { id: "rrt-pa-013", stem: "What is the normal range for end-tidal CO2 (ETCO2) and what does a sudden drop to near-zero indicate?", options: ["Normal 35-45 mmHg; sudden drop to near-zero indicates esophageal intubation, ETT displacement, or cardiac arrest", "Normal 20-25 mmHg; drop indicates hyperventilation", "Normal 50-60 mmHg; drop indicates improved ventilation", "ETCO2 has no clinical significance"], correctIndex: 0, rationale: "Normal ETCO2: 35-45 mmHg (usually 2-5 mmHg less than PaCO2). A sudden drop to near-zero indicates: (1) Esophageal intubation (no CO2 in stomach), (2) ETT displacement/disconnection, (3) Cardiac arrest (no pulmonary blood flow to deliver CO2 to lungs), (4) Complete airway obstruction. ETCO2 is the gold standard for ETT placement confirmation.", difficulty: 2, category: "Patient Assessment", topic: "Capnography Monitoring", questionType: "multiple-choice", examTip: "ETCO2 drop to near-zero: esophageal intubation, ETT dislodged, cardiac arrest. Gold standard for ETT confirmation." },
  { id: "rrt-pa-014", stem: "What is the significance of a 'water bottle' cardiac silhouette on chest X-ray?", options: ["Pericardial effusion with enlarged, flask-shaped cardiac silhouette", "Normal cardiac size", "Left ventricular hypertrophy", "Pneumomediastinum"], correctIndex: 0, rationale: "A 'water bottle' or flask-shaped cardiac silhouette on CXR indicates pericardial effusion — fluid surrounding the heart enlarges the cardiac shadow uniformly. Large effusions may cause cardiac tamponade. Clinical correlation includes Beck's triad (hypotension, JVD, muffled heart sounds) and pulsus paradoxus (> 10 mmHg BP drop during inspiration).", difficulty: 3, category: "Patient Assessment", topic: "Chest X-Ray Interpretation", questionType: "multiple-choice", examTip: "Water bottle silhouette = pericardial effusion. Check for tamponade: Beck's triad + pulsus paradoxus." },
  { id: "rrt-pa-015", stem: "During auscultation, the RT hears a high-pitched 'pleural friction rub.' What does this indicate?", options: ["Inflamed visceral and parietal pleurae rubbing together, as in pleurisy or pulmonary embolism", "Bronchospasm", "Consolidated pneumonia", "Pneumothorax"], correctIndex: 0, rationale: "A pleural friction rub is a grating, creaking sound heard during both inspiration and expiration when inflamed pleural surfaces rub against each other. Causes include pleurisy, pulmonary embolism/infarction, pneumonia, and pleural tumors. It disappears when fluid accumulates between the layers (pleural effusion 'silences' the rub).", difficulty: 2, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "multiple-choice", examTip: "Pleural friction rub: grating sound on inspiration AND expiration. Pleurisy, PE, pneumonia. Disappears with effusion." },
  { id: "rrt-pa-016", stem: "A patient has the following vital signs: RR 28, HR 110, BP 90/60, SpO2 91%, temperature 38.8°C, WBC 14,000. Using the qSOFA score, what is the score and clinical significance?", options: ["qSOFA score of 2 (RR ≥ 22, SBP ≤ 100) — meets criteria for suspected sepsis, need further workup", "qSOFA score of 0 — normal findings", "qSOFA score of 3 — immediate intubation required", "qSOFA is not used in respiratory care"], correctIndex: 0, rationale: "qSOFA (quick Sequential Organ Failure Assessment) criteria: (1) RR ≥ 22 (+1), (2) Altered mentation (+1), (3) SBP ≤ 100 mmHg (+1). This patient: RR 28 (≥ 22, +1), SBP 90 (≤ 100, +1), mentation not stated but assumed alert = score 2. qSOFA ≥ 2 identifies patients at risk for poor outcomes and should prompt full SOFA assessment, lactate, and blood cultures.", difficulty: 3, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "case-based", examTip: "qSOFA: RR ≥ 22, altered mentation, SBP ≤ 100. Score ≥ 2 = suspected sepsis. Quick bedside tool." },
  { id: "rrt-ic-013", stem: "What is the recommended minimum air exchanges per hour for an airborne isolation room?", options: ["12 air changes per hour (ACH) with negative pressure relative to surrounding areas", "2 air changes per hour", "6 air changes per hour", "20 air changes per hour"], correctIndex: 0, rationale: "Airborne isolation (AII) rooms require: ≥ 12 ACH (6 ACH minimum for existing facilities), negative pressure relative to corridors, air exhausted to outside or through HEPA filter, and the door kept closed. Used for TB, measles, varicella, COVID-19 (aerosol-generating procedures). Healthcare workers wear N95 or PAPR.", difficulty: 2, category: "Infection Control & Equipment", topic: "Isolation Precautions", questionType: "multiple-choice", examTip: "Airborne isolation room: ≥ 12 ACH, negative pressure, HEPA-filtered exhaust, door closed. N95 required." },
  { id: "rrt-ic-014", stem: "What organisms require airborne precautions?", options: ["Tuberculosis (TB), measles (rubeola), varicella (chickenpox), and disseminated herpes zoster", "Influenza and RSV", "MRSA and C. difficile", "E. coli and Klebsiella"], correctIndex: 0, rationale: "Airborne precautions are required for diseases transmitted via small droplet nuclei (< 5 microns) that remain suspended in air: MTB (tuberculosis), measles (rubeola), varicella (chickenpox), and disseminated herpes zoster (shingles). These require: negative pressure room, ≥ 12 ACH, N95 respirator or PAPR. Influenza requires droplet precautions.", difficulty: 2, category: "Infection Control & Equipment", topic: "Isolation Precautions", questionType: "multiple-choice", examTip: "Airborne precautions: TB, measles, varicella, disseminated zoster. Remember: 'MTV' + varicella." },
  { id: "rrt-ic-015", stem: "How should a respiratory therapist properly don and doff PPE when entering a droplet precautions room?", options: ["Don: hand hygiene → gown → mask → eye protection → gloves. Doff: gloves → eye protection → gown → mask → hand hygiene", "Put on all PPE simultaneously in any order", "Only gloves and mask are required for droplet precautions", "PPE is only required for airborne precautions"], correctIndex: 0, rationale: "Correct donning sequence: (1) Hand hygiene, (2) Gown, (3) Mask/respirator, (4) Eye protection (goggles/shield), (5) Gloves (over gown cuffs). Doffing (reverse, most contaminated first): (1) Gloves, (2) Eye protection, (3) Gown, (4) Mask/respirator, (5) Hand hygiene. Avoid self-contamination during doffing — this is the highest-risk step.", difficulty: 2, category: "Infection Control & Equipment", topic: "Hand Hygiene Protocols", questionType: "multiple-choice", examTip: "PPE order — Don: gown → mask → goggles → gloves. Doff (reverse): gloves → goggles → gown → mask. Hand hygiene first and last." },
  { id: "rrt-mv-046", stem: "What does PAV+ (Proportional Assist Ventilation Plus) provide that other modes do not?", options: ["Automatically calculates and adjusts support proportional to patient effort using real-time compliance and resistance measurements", "Fixed pressure support regardless of effort", "Mandatory breaths at set intervals", "Inverse ratio ventilation"], correctIndex: 0, rationale: "PAV+ measures respiratory system compliance and resistance in real-time and delivers pressure proportional to the patient's instantaneous effort. More effort = more support; less effort = less support. This provides excellent patient-ventilator synchrony and can be used for weaning. The ventilator does the monitoring automatically.", difficulty: 5, category: "Mechanical Ventilation", topic: "Ventilation Modes", questionType: "multiple-choice", examTip: "PAV+ = support proportional to patient effort. Real-time C and R measurement. Excellent synchrony." },
  { id: "rrt-mv-047", stem: "A patient on AC/VC has flow set at 60 L/min with a square waveform. Changing to a decelerating waveform at the same peak flow would have what effect?", options: ["Lower peak airway pressure (PIP) with unchanged Pplat", "Higher PIP with unchanged Pplat", "No change in any pressure", "Lower Pplat with unchanged PIP"], correctIndex: 0, rationale: "Decelerating flow delivers flow quickly at the start of inspiration (meeting patient demand) then gradually decreases. This distributes the tidal volume more evenly, resulting in lower PIP compared to square (constant) waveform at the same peak flow setting. However, Pplat remains unchanged (same Vt and compliance). Inspiratory time is longer with decelerating flow.", difficulty: 4, category: "Mechanical Ventilation", topic: "Waveform Analysis", questionType: "multiple-choice", examTip: "Decelerating flow: lower PIP (better gas distribution), same Pplat, longer I-time vs square waveform." },
  { id: "rrt-mv-048", stem: "What is the recommended initial ventilator settings for a COPD patient requiring intubation?", options: ["Vt 6-8 mL/kg IBW, RR 10-14, low PEEP (matching auto-PEEP ~80%), I:E ≥ 1:3", "Vt 12 mL/kg, RR 20, PEEP 15, I:E 1:1", "Vt 4 mL/kg, RR 30, PEEP 20", "No specific recommendations for COPD"], correctIndex: 0, rationale: "COPD ventilation strategy: moderate Vt (6-8 mL/kg IBW), low RR (10-14) to allow adequate exhalation time, I:E ≥ 1:3 (preferably 1:4), low-moderate PEEP (set at approximately 80% of auto-PEEP to reduce triggering work), and permissive hypercapnia if needed. Goal: prevent air trapping and auto-PEEP while maintaining adequate ventilation.", difficulty: 3, category: "Mechanical Ventilation", topic: "Initial Settings", questionType: "multiple-choice", examTip: "COPD initial vent settings: moderate Vt, LOW RR, LONG E-time (I:E ≥ 1:3), low PEEP matching auto-PEEP." },
  { id: "rrt-abg-031", stem: "ABG results: pH 7.40, PaCO2 40, HCO3 24, PaO2 60, SaO2 90% on room air. What is significant about these results?", options: ["Hypoxemia with normal acid-base status — investigate cause (V/Q mismatch, shunt, diffusion impairment)", "Completely normal ABG — no action needed", "Respiratory alkalosis requiring treatment", "Metabolic acidosis"], correctIndex: 0, rationale: "The acid-base is normal (pH, PaCO2, HCO3 all normal). However, PaO2 of 60 mmHg on room air is below normal (80-100 mmHg) and SaO2 of 90% is borderline. This indicates an oxygenation problem (hypoxemia) despite normal ventilation. Calculate P(A-a)O2 gradient to help determine the cause: V/Q mismatch, shunt, or diffusion impairment.", difficulty: 3, category: "ABG Interpretation", topic: "acid-base analysis", questionType: "case-based", examTip: "Always assess BOTH acid-base AND oxygenation on ABG. Normal pH doesn't mean normal oxygenation." },
  { id: "rrt-abg-032", stem: "What is the normal P(A-a)O2 gradient and how does it help differentiate causes of hypoxemia?", options: ["Normal < 10-15 mmHg on room air; elevated P(A-a) = parenchymal disease; normal P(A-a) + hypoxemia = hypoventilation", "Normal > 30 mmHg", "Not clinically useful", "Only measured during exercise testing"], correctIndex: 0, rationale: "A-a gradient = PAO2 - PaO2. Normal: < 10-15 mmHg (increases ~3 mmHg per decade of age). Elevated A-a gradient = parenchymal cause (V/Q mismatch, shunt, diffusion impairment). Normal A-a gradient + hypoxemia = extrapulmonary cause (hypoventilation, altitude, low FiO2). This is a critical diagnostic tool.", difficulty: 4, category: "ABG Interpretation", topic: "acid-base analysis", questionType: "multiple-choice", examTip: "A-a gradient: normal = hypoventilation cause. Elevated = lung parenchymal disease (V/Q mismatch, shunt)." },
  { id: "rrt-o2-022", stem: "What is absorptive atelectasis and how does it relate to oxygen therapy?", options: ["Alveolar collapse from nitrogen washout when breathing high FiO2, as oxygen is rapidly absorbed", "Atelectasis from mucus plugging", "Compression of lung from pleural effusion", "Post-surgical atelectasis from shallow breathing"], correctIndex: 0, rationale: "When breathing high FiO2 (especially 1.0), nitrogen (which normally 'splints' alveoli open due to its slow absorption) is washed out and replaced by oxygen. In poorly ventilated alveoli, the oxygen is rapidly absorbed into the blood, and without nitrogen to maintain alveolar volume, the alveolus collapses. This is why FiO2 should be reduced to the lowest effective level.", difficulty: 3, category: "Oxygen Therapy", topic: "Titration Protocols", questionType: "multiple-choice", examTip: "Absorptive atelectasis: high FiO2 washes out N2 → rapid O2 absorption → alveolar collapse. Keep FiO2 minimal." },
  { id: "rrt-aw-021", stem: "What is the Mallampati classification and how does it predict intubation difficulty?", options: ["Visual assessment of oropharyngeal structures with mouth open; Class I (full view) to Class IV (only hard palate visible) — higher class = more difficult intubation", "X-ray classification of cervical spine alignment", "Grading system for laryngeal edema", "Assessment of nasal airway patency"], correctIndex: 0, rationale: "Mallampati classification (patient sitting, mouth open wide, tongue protruded, no phonation): Class I: soft palate, fauces, uvula, pillars visible. Class II: soft palate, fauces, uvula. Class III: soft palate, base of uvula. Class IV: hard palate only. Higher class correlates with more difficult intubation. Assessed pre-intubation as part of airway evaluation.", difficulty: 2, category: "Airway Management", topic: "Airway Assessment", questionType: "multiple-choice", examTip: "Mallampati: I (see everything) to IV (hard palate only). III-IV predicts difficult intubation." },
  { id: "rrt-aw-022", stem: "What is a bougie (tracheal introducer) used for?", options: ["Facilitating difficult intubation by providing a guide for ETT advancement when glottic view is poor", "Suctioning the trachea", "Performing tracheostomy", "Measuring tracheal diameter"], correctIndex: 0, rationale: "A bougie (Eschmann tracheal introducer) is a semi-rigid curved guide placed through the glottis when direct visualization is limited (Cormack-Lehane Grade III). The RT slides the bougie along the anterior tracheal wall (feeling clicks over cartilaginous rings = confirms tracheal placement), then railroads the ETT over it. Essential tool in difficult airway management.", difficulty: 2, category: "Airway Management", topic: "Endotracheal Intubation", questionType: "multiple-choice", examTip: "Bougie: guide for difficult intubation. Feel tracheal ring clicks to confirm placement. Railroad ETT over it." },
  { id: "rrt-pft-016", stem: "What is methacholine challenge testing used for?", options: ["Diagnosing airway hyperresponsiveness consistent with asthma when baseline spirometry is normal", "Diagnosing COPD severity", "Measuring lung volumes in restrictive disease", "Assessing diffusion capacity"], correctIndex: 0, rationale: "Methacholine challenge (bronchoprovocation test) is used when asthma is suspected but baseline spirometry is normal. The patient inhales increasing concentrations of methacholine (a cholinergic bronchoconstrictor). A positive test: PC20 (provocative concentration causing 20% FEV1 drop) < 4-8 mg/mL indicates airway hyperresponsiveness, supporting asthma diagnosis. The test is very sensitive (~95%) but less specific.", difficulty: 3, category: "Pulmonary Function Testing", topic: "Exercise Testing", questionType: "multiple-choice", examTip: "Methacholine challenge: asthma suspected with normal spirometry. PC20 < 4-8 mg/mL = positive (hyperresponsive)." },
  { id: "rrt-neo-022", stem: "What are the target SpO2 ranges for preterm neonates to prevent retinopathy of prematurity (ROP)?", options: ["88-95% to balance adequate oxygenation while minimizing hyperoxia-related complications", "96-100% for maximum oxygenation", "80-85% to minimize all oxygen exposure", "No specific target — use clinical judgment"], correctIndex: 0, rationale: "Preterm neonates are at risk for ROP from hyperoxia. Current evidence (SUPPORT, BOOST II, COT trials) supports targeting SpO2 88-95% (some use 91-95%). Higher targets (> 95%) increase ROP risk; lower targets (85-89%) increase mortality. The optimal range balances prevention of ROP against minimizing mortality risk.", difficulty: 3, category: "Neonatal & Pediatric Respiratory Care", topic: "Neonatal Resuscitation", questionType: "multiple-choice", examTip: "Preterm SpO2 target: 88-95%. > 95% = ROP risk. < 88% = mortality risk. Tight targeting is critical." },
  { id: "rrt-neo-023", stem: "Croup presents with which classic triad of symptoms?", options: ["Barky (seal-like) cough, inspiratory stridor, and hoarseness — usually in children 6 months to 3 years", "Expiratory wheezing, productive cough, and fever", "Drooling, tripod positioning, and high fever", "Silent chest, cyanosis, and altered consciousness"], correctIndex: 0, rationale: "Croup (laryngotracheobronchitis) classic triad: barky/seal-like cough, inspiratory stridor (upper airway narrowing), and hoarseness (laryngeal inflammation). CXR shows 'steeple sign' (subglottic narrowing). Most common in ages 6 months to 3 years. Treatment: dexamethasone (0.6 mg/kg PO/IM) ± nebulized racemic epinephrine for moderate-severe cases.", difficulty: 2, category: "Neonatal & Pediatric Respiratory Care", topic: "Croup and Epiglottitis", questionType: "multiple-choice", examTip: "Croup: barky cough + stridor + hoarseness + steeple sign. Ages 6mo-3yr. Dex ± racemic epi." },
  { id: "rrt-cc-022", stem: "What is the RASS (Richmond Agitation-Sedation Scale) target for most mechanically ventilated patients?", options: ["RASS 0 to -2 (calm to light sedation) per current PADIS guidelines", "RASS -5 (deep sedation/unarousable) for all patients", "RASS +4 (combative) is acceptable during ventilation", "No sedation assessment scale is recommended"], correctIndex: 0, rationale: "Current PADIS guidelines recommend light sedation (RASS 0 to -2) for most mechanically ventilated patients. RASS scores range from +4 (combative) to -5 (unarousable). Light sedation is associated with shorter ventilator days, shorter ICU stay, and improved outcomes compared to deep sedation. Daily sedation interruption (SAT) is part of the ABCDEF bundle.", difficulty: 2, category: "Critical Care Respiratory Therapy", topic: "Sedation and Paralysis", questionType: "multiple-choice", examTip: "RASS target: 0 to -2 (calm to light sedation). Deep sedation increases vent days and delirium." },
  { id: "rrt-cp-021", stem: "What is the oxygen-hemoglobin dissociation curve and what is the significance of the P50?", options: ["Sigmoidal curve showing Hb-O2 relationship; P50 is the PO2 at which Hb is 50% saturated (normal ~27 mmHg)", "Linear relationship between PO2 and SaO2", "P50 is the maximum oxygen carrying capacity", "The curve is only relevant at sea level"], correctIndex: 0, rationale: "The oxyhemoglobin dissociation curve is sigmoidal (S-shaped), reflecting cooperative binding. P50 = PO2 at 50% saturation ≈ 27 mmHg. Right shift (increased P50 > 27): easier O2 unloading to tissues (acidosis, fever, high 2,3-DPG). Left shift (decreased P50 < 27): harder O2 unloading (alkalosis, hypothermia, low 2,3-DPG, CO, HbF).", difficulty: 3, category: "Cardiopulmonary Physiology", topic: "Oxyhemoglobin Dissociation Curve", questionType: "multiple-choice", examTip: "P50 = 27 mmHg (50% saturation). Right shift: P50 > 27 (easier O2 release). Left shift: P50 < 27 (tighter binding)." },
  { id: "rrt-aer-017", stem: "What is the correct technique for using an MDI with a spacer?", options: ["Shake MDI, prime if new, insert into spacer, exhale fully, actuate once, inhale slowly and deeply over 3-5 seconds, hold breath 10 seconds", "Exhale into the spacer, then actuate and inhale rapidly", "Actuate the MDI 3-4 times into the spacer, then take one breath", "Use the MDI upside down and inhale rapidly"], correctIndex: 0, rationale: "Correct MDI + spacer technique: (1) Shake MDI well, (2) Prime if first use or not used in > 2 weeks, (3) Insert MDI into spacer, (4) Exhale fully, (5) Place spacer mouthpiece in mouth, (6) Actuate ONE puff, (7) Inhale slowly and deeply over 3-5 seconds, (8) Hold breath 10 seconds, (9) Wait 30-60 seconds between puffs. Avoid rapid inhalation with spacer.", difficulty: 1, category: "Aerosol & Medication Delivery", topic: "Metered-Dose Inhalers", questionType: "multiple-choice", examTip: "MDI + spacer: 1 puff, slow deep inhalation (3-5 sec), hold breath 10 sec. Not multiple puffs at once." },
  { id: "rrt-sniv-016", stem: "What is Cheyne-Stokes respiration and what central sleep apnea treatment is indicated?", options: ["Crescendo-decrescendo breathing pattern with apneic pauses; treated with adaptive servo-ventilation (ASV) or BiPAP-ST", "Rapid shallow breathing treated with CPAP", "Irregular breathing treated with oxygen alone", "Normal breathing pattern during sleep"], correctIndex: 0, rationale: "Cheyne-Stokes respiration (CSR) is a crescendo-decrescendo breathing pattern with central apneic pauses, often associated with heart failure or stroke. Treatment: adaptive servo-ventilation (ASV) — automatically adjusts PS to stabilize breathing. Note: ASV is CONTRAINDICATED in HFrEF (EF < 45%) per the SERVE-HF trial (increased cardiovascular mortality). Use BiPAP-ST for HFrEF patients.", difficulty: 4, category: "Sleep & Noninvasive Ventilation", topic: "Home Ventilation", questionType: "multiple-choice", examTip: "CSR + HF: ASV only if EF > 45%. ASV CONTRAINDICATED in HFrEF (EF < 45%) — use BiPAP-ST instead." },
  { id: "rrt-em-020", stem: "What is the first-line treatment for anaphylaxis?", options: ["Epinephrine 0.3-0.5 mg IM (1:1,000) into the anterolateral thigh", "IV diphenhydramine 50 mg", "Albuterol nebulization", "IV methylprednisolone 125 mg"], correctIndex: 0, rationale: "Epinephrine IM is the FIRST-LINE and MOST IMPORTANT treatment for anaphylaxis. Give 0.3-0.5 mg (1:1,000 concentration) IM into the anterolateral thigh (vastus lateralis). May repeat every 5-15 minutes. Do NOT delay for other interventions (antihistamines, steroids are adjuncts). Common error: giving antihistamines first instead of epinephrine.", difficulty: 2, category: "Emergency Respiratory Care", topic: "Anaphylaxis Airway Management", questionType: "multiple-choice", examTip: "Anaphylaxis #1 treatment: IM EPINEPHRINE first. Not antihistamines, not steroids. IM thigh, may repeat q5-15 min." },
  { id: "rrt-pa-017", stem: "What is the Modified Borg Scale used for in respiratory assessment?", options: ["Patient self-reported dyspnea severity on a 0-10 scale during activity or pulmonary function testing", "Oxygen saturation monitoring", "Blood pressure classification", "Heart rate zone determination"], correctIndex: 0, rationale: "The Modified Borg Scale (0-10) is a validated tool for patients to rate their perceived breathlessness: 0 = nothing at all, 2 = slight, 5 = severe, 10 = maximal. Used during 6MWT, pulmonary rehab, and exercise testing. It is subjective but correlates well with objective measures of respiratory function and helps guide therapy.", difficulty: 1, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "multiple-choice", examTip: "Modified Borg: 0-10 dyspnea self-report. Used in 6MWT and pulmonary rehab. 0=none, 10=maximal." },
  { id: "rrt-ic-016", stem: "What is the proper procedure for N95 fit testing?", options: ["Annual fit testing using qualitative (taste) or quantitative methods to ensure proper seal for each individual", "Visual inspection only", "One-size-fits-all — no fit testing needed", "Fit testing is only required every 5 years"], correctIndex: 0, rationale: "OSHA requires annual N95 fit testing for healthcare workers. Methods: qualitative (Bitrex taste or saccharin solution — pass/fail) or quantitative (machine-measured fit factor ≥ 100). A seal check (positive and negative pressure) is performed EVERY TIME the N95 is donned. Fit testing ensures the specific N95 model creates an adequate seal for the individual's face shape.", difficulty: 2, category: "Infection Control & Equipment", topic: "Hand Hygiene Protocols", questionType: "multiple-choice", examTip: "N95 fit testing: annual, qualitative or quantitative. Seal check every time you put it on." },
  { id: "rrt-mv-049", stem: "What is the difference between flow triggering and pressure triggering on a ventilator?", options: ["Flow triggering detects a decrease in circuit flow; pressure triggering detects a drop in circuit pressure. Flow triggering requires less patient effort.", "They are identical mechanisms", "Pressure triggering is always superior", "Flow triggering is only available on neonatal ventilators"], correctIndex: 0, rationale: "Flow triggering: a continuous base flow circulates through the circuit; the ventilator detects when the patient's inspiratory effort decreases the return flow by the set sensitivity (e.g., 2 L/min). Pressure triggering: detects a drop in circuit pressure below the set threshold (e.g., -1 to -2 cmH2O). Flow triggering generally requires less work of breathing and is preferred in most situations.", difficulty: 3, category: "Mechanical Ventilation", topic: "Initial Settings", questionType: "multiple-choice", examTip: "Flow triggering: less WOB, uses base flow. Pressure triggering: detects pressure drop. Flow generally preferred." },
  { id: "rrt-mv-050", stem: "A patient on mechanical ventilation has the following: PIP 35, Pplat 18, PEEP 5. Calculate the static compliance.", options: ["31 mL/cmH2O (assuming Vt 400 mL)", "80 mL/cmH2O", "13 mL/cmH2O", "57 mL/cmH2O"], correctIndex: 0, rationale: "Static compliance (Cst) = Vt / (Pplat - PEEP) = 400 / (18 - 5) = 400 / 13 = 30.8 ≈ 31 mL/cmH2O. Normal Cst: 60-100 mL/cmH2O. This patient's reduced compliance suggests parenchymal disease (ARDS, pulmonary fibrosis, atelectasis). Dynamic compliance = Vt / (PIP - PEEP) = 400 / 30 = 13.3 (includes both compliance and resistance effects).", difficulty: 2, category: "Mechanical Ventilation", topic: "Ventilator Calculations", questionType: "multiple-choice", examTip: "Cst = Vt / (Pplat - PEEP). Normal 60-100. Cdyn = Vt / (PIP - PEEP). Compare both to distinguish compliance vs resistance." },
  { id: "rrt-abg-033", stem: "A COPD patient on home O2 at 2L has ABG: pH 7.35, PaCO2 52, HCO3 28, PaO2 62. Is this ABG acceptable for this patient?", options: ["Yes — this shows compensated chronic respiratory acidosis with acceptable oxygenation for COPD", "No — the patient needs mechanical ventilation immediately", "No — the pH indicates acute acidosis", "No — the PaO2 is too high for a COPD patient"], correctIndex: 0, rationale: "This shows fully compensated chronic respiratory acidosis: pH 7.35 (low-normal), PaCO2 52 (chronically elevated), HCO3 28 (renal compensation). PaO2 of 62 is acceptable for a COPD patient on supplemental O2 (target SpO2 88-92%). This is a stable baseline for a chronic CO2 retainer — no acute intervention needed.", difficulty: 3, category: "ABG Interpretation", topic: "acid-base analysis", questionType: "case-based", examTip: "Compensated chronic resp acidosis in COPD: pH near normal, PaCO2 elevated, HCO3 elevated. PaO2 55-65 acceptable." },
  { id: "rrt-o2-023", stem: "An air entrainment mask is set to deliver 35% FiO2. If the entrainment port is partially blocked, what happens?", options: ["The FiO2 increases above 35% because less room air is entrained", "The FiO2 decreases below 35%", "There is no effect on FiO2", "The patient receives no oxygen"], correctIndex: 0, rationale: "Air entrainment (Venturi) masks work by entraining room air through jet mixing. If the entrainment port is blocked (water, mucus, or position), less room air is mixed with the oxygen stream, resulting in a HIGHER FiO2 than intended. Additionally, total flow decreases, which may not meet patient inspiratory demand. Always keep ports unobstructed.", difficulty: 2, category: "Oxygen Therapy", topic: "Delivery Devices", questionType: "multiple-choice", examTip: "Blocked Venturi port: FiO2 INCREASES (less air entrained) and total flow DECREASES. Keep ports clear." },
  { id: "rrt-aw-023", stem: "What is the purpose of a cuff leak test before extubation?", options: ["To assess for upper airway edema that may cause post-extubation stridor", "To test ventilator function", "To measure tidal volume accuracy", "To assess vocal cord function"], correctIndex: 0, rationale: "The cuff leak test assesses for laryngeal edema that may cause post-extubation stridor. Method: deflate the ETT cuff and observe/listen for air leak around the tube (positive test = air leak present = likely no significant edema). A positive leak indicates the airway is likely patent enough for safe extubation. Absent leak suggests edema — consider corticosteroids before extubation.", difficulty: 2, category: "Airway Management", topic: "Endotracheal Intubation", questionType: "multiple-choice", examTip: "Cuff leak test: deflate cuff, listen for leak. Leak present = safe to extubate. No leak = possible edema." },
  { id: "rrt-pft-017", stem: "What is the maximum voluntary ventilation (MVV) test and what does it measure?", options: ["Patient breathes as deeply and rapidly as possible for 12-15 seconds; measures ventilatory endurance and capacity", "Resting tidal volume measurement", "Breath-hold time for diving assessment", "Oxygen consumption at rest"], correctIndex: 0, rationale: "MVV measures the maximum volume of air a patient can breathe in 12-15 seconds (extrapolated to 1 minute). It reflects: respiratory muscle strength, airway resistance, lung compliance, and ventilatory reserve. MVV is used to assess surgical risk, disability evaluation, and exercise capacity. Estimated MVV ≈ FEV1 × 35-40.", difficulty: 2, category: "Pulmonary Function Testing", topic: "Spirometry", questionType: "multiple-choice", examTip: "MVV: max breathing for 12-15 sec. Estimates ventilatory reserve. Approximate MVV = FEV1 × 35-40." },
  { id: "rrt-neo-024", stem: "What is the most important initial step in neonatal resuscitation per NRP?", options: ["Provide warmth, clear airway if needed, dry and stimulate the infant", "Immediate intubation and ventilation", "IV epinephrine administration", "Chest compressions"], correctIndex: 0, rationale: "NRP initial steps (within first 30 seconds): (1) Provide warmth (radiant warmer), (2) Position head/neck (sniffing position), (3) Clear airway if needed (suction only if obstructed), (4) Dry thoroughly, (5) Stimulate (flick feet, rub back). Most neonates respond to these initial steps. Only 10% require positive pressure ventilation, and < 1% require chest compressions.", difficulty: 2, category: "Neonatal & Pediatric Respiratory Care", topic: "Neonatal Resuscitation", questionType: "multiple-choice", examTip: "NRP first 30 sec: warm, position, clear airway, dry, stimulate. 90% respond. Only 10% need PPV." },
  { id: "rrt-cc-023", stem: "What is the recommended recruitment maneuver for ARDS?", options: ["Sustained inflation at 30-40 cmH2O for 30-40 seconds or incremental PEEP titration", "Brief high-frequency oscillation", "Prone positioning only", "Deep suctioning"], correctIndex: 0, rationale: "Recruitment maneuvers in ARDS aim to open collapsed alveoli. Methods: (1) Sustained inflation (CPAP 30-40 cmH2O for 30-40 seconds), (2) Incremental PEEP titration (stepwise increase then decrease, finding the 'open lung' PEEP), (3) Sigh breaths. Monitor closely — may cause hypotension, pneumothorax. ART trial showed staircase recruitment may be harmful; individual patient assessment is essential.", difficulty: 4, category: "Critical Care Respiratory Therapy", topic: "ARDS Management", questionType: "multiple-choice", examTip: "Recruitment: sustained inflation 30-40 cmH2O for 30-40 sec. Monitor hemodynamics. Individual response varies." },
  { id: "rrt-cp-022", stem: "What is the difference between Type I and Type II respiratory failure?", options: ["Type I = hypoxemic (PaO2 < 60) with normal/low PaCO2; Type II = hypercapnic (PaCO2 > 45) ± hypoxemia", "Type I and II are identical", "Type I = chronic; Type II = acute", "Type I = upper airway; Type II = lower airway"], correctIndex: 0, rationale: "Type I (hypoxemic) respiratory failure: PaO2 < 60 mmHg with normal or low PaCO2 (adequate ventilation but impaired oxygenation). Causes: pneumonia, ARDS, PE, ILD. Type II (hypercapnic/ventilatory) failure: PaCO2 > 45 mmHg ± hypoxemia (inadequate ventilation). Causes: COPD, neuromuscular disease, drug overdose, obesity hypoventilation.", difficulty: 2, category: "Cardiopulmonary Physiology", topic: "Gas Exchange Physiology", questionType: "multiple-choice", examTip: "Type I: hypoxemic (PaO2 < 60, normal CO2). Type II: hypercapnic (PaCO2 > 45 ± low PaO2)." },
  { id: "rrt-aer-018", stem: "What is the drug class and mechanism of action of budesonide (Pulmicort)?", options: ["Inhaled corticosteroid — reduces airway inflammation by suppressing inflammatory mediator release", "Short-acting beta-2 agonist", "Long-acting muscarinic antagonist", "Leukotriene receptor antagonist"], correctIndex: 0, rationale: "Budesonide (Pulmicort) is an inhaled corticosteroid (ICS). Mechanism: suppresses inflammatory gene expression, reduces eosinophil infiltration, decreases airway edema and mucus production. Used for maintenance therapy in asthma and sometimes COPD. NOT a rescue medication — requires 1-4 weeks for full effect. Side effects: oral candidiasis, dysphonia. Rinse mouth after use.", difficulty: 2, category: "Aerosol & Medication Delivery", topic: "Bronchodilator Therapy", questionType: "multiple-choice", examTip: "Budesonide (Pulmicort): ICS, maintenance only, NOT rescue. Rinse mouth after use (prevents candidiasis)." },
  { id: "rrt-em-021", stem: "What are the H's and T's — reversible causes of cardiac arrest?", options: ["H's: Hypovolemia, Hypoxia, H+ (acidosis), Hypo/hyperkalemia, Hypothermia. T's: Tension pneumo, Tamponade, Toxins, Thrombosis (PE/MI)", "H's and T's refer to medication classes", "H's are heart conditions; T's are trauma conditions", "H's and T's are ventilator settings"], correctIndex: 0, rationale: "The H's and T's are reversible causes of cardiac arrest that must be identified and treated during CPR: H's: Hypovolemia, Hypoxia, Hydrogen ion (acidosis), Hypo/hyperkalemia, Hypothermia. T's: Tension pneumothorax, Tamponade (cardiac), Toxins (drug overdose), Thrombosis (pulmonary embolism or coronary). Treating the underlying cause is essential for ROSC.", difficulty: 2, category: "Emergency Respiratory Care", topic: "CPR/ACLS Protocols", questionType: "multiple-choice", examTip: "H's and T's: 5 H's + 4 T's. Must identify and treat during CPR. Essential for ROSC." },
  { id: "rrt-pa-018", stem: "What is pulsus paradoxus and in which conditions is it seen?", options: ["Exaggerated (> 10 mmHg) drop in systolic BP during inspiration; seen in cardiac tamponade, severe asthma, and COPD", "Irregular pulse rhythm", "Bounding peripheral pulses", "Absent pedal pulses"], correctIndex: 0, rationale: "Pulsus paradoxus is an exaggerated (> 10 mmHg) decrease in systolic BP during inspiration. It occurs because inspiration increases negative intrathoracic pressure, pooling blood in the pulmonary vasculature and reducing LV filling. Exaggerated in: cardiac tamponade (classic), severe asthma/COPD, constrictive pericarditis, and tension pneumothorax.", difficulty: 3, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "multiple-choice", examTip: "Pulsus paradoxus: SBP drops > 10 mmHg with inspiration. Tamponade, severe asthma, constrictive pericarditis." },
  { id: "rrt-ic-017", stem: "How often should ventilator circuits be changed to prevent VAP?", options: ["Only when visibly soiled or malfunctioning — routine scheduled changes are NOT recommended", "Every 24 hours", "Every 48 hours", "Every 7 days routinely"], correctIndex: 0, rationale: "Evidence-based guidelines recommend changing ventilator circuits ONLY when visibly soiled or malfunctioning. Routine scheduled circuit changes do NOT reduce VAP rates and may actually increase infection risk through manipulation. Inline suction catheters should remain in place until soiled. HMEs should be changed every 24-48 hours or when visibly contaminated.", difficulty: 2, category: "Infection Control & Equipment", topic: "VAP Prevention Bundle", questionType: "multiple-choice", examTip: "Vent circuits: change ONLY when soiled. Routine changes do NOT prevent VAP. In-line suction: leave in place." },
  { id: "rrt-mv-051", stem: "What is the clinical significance of the stress index in pressure-controlled ventilation?", options: ["It assesses whether lung recruitment or overdistension is occurring during tidal ventilation based on the pressure-time curve shape", "It measures patient comfort level", "It calculates FiO2 requirements", "It determines weaning readiness"], correctIndex: 0, rationale: "The stress index analyzes the pressure-time curve shape during constant-flow ventilation: Stress index < 1 (downward concavity) = tidal recruitment occurring (may benefit from more PEEP). Stress index = 1 (straight line) = optimal ventilation. Stress index > 1 (upward convexity) = overdistension occurring (reduce Vt or PEEP). It helps optimize PEEP and Vt settings.", difficulty: 5, category: "Mechanical Ventilation", topic: "Waveform Analysis", questionType: "multiple-choice", examTip: "Stress index: < 1 = recruitment (increase PEEP), = 1 = optimal, > 1 = overdistension (decrease PEEP/Vt)." },
  { id: "rrt-abg-034", stem: "A patient receiving TPN (total parenteral nutrition) has ABG: pH 7.48, PaCO2 30, HCO3 22. RQ is elevated at 1.2. What is causing the respiratory alkalosis?", options: ["Excess carbohydrate calories in TPN increasing CO2 production, causing compensatory hyperventilation", "Metabolic alkalosis from bicarbonate in TPN", "Anxiety-driven hyperventilation", "Ventilator over-ventilation"], correctIndex: 0, rationale: "Excessive carbohydrate calories in TPN increase the respiratory quotient (RQ > 1.0), producing more CO2 than normal metabolic processes. The body compensates by hyperventilating to eliminate excess CO2, resulting in respiratory alkalosis. The solution is to replace some carbohydrate calories with fat calories in the TPN formulation (fat RQ = 0.7).", difficulty: 4, category: "ABG Interpretation", topic: "acid-base analysis", questionType: "case-based", examTip: "High RQ from excess TPN carbs → increased CO2 production → respiratory alkalosis. Replace carbs with fat." },
  { id: "rrt-o2-024", stem: "What is the reservoir capacity of a non-rebreather mask and what FiO2 does it deliver?", options: ["600-1000 mL reservoir bag delivers up to 60-80% FiO2 at 10-15 L/min flow", "100 mL reservoir delivers 24% FiO2", "No reservoir needed — delivers 100% FiO2", "2000 mL reservoir delivers 100% FiO2"], correctIndex: 0, rationale: "A non-rebreather mask (NRB) has a 600-1000 mL reservoir bag with one-way valves on the exhalation ports (preventing room air entrainment). At 10-15 L/min, it delivers approximately 60-80% FiO2 (NOT 100% due to mask fit imperfections). The reservoir must remain at least 1/3 full during inspiration. Higher flows and tighter fit increase delivered FiO2.", difficulty: 2, category: "Oxygen Therapy", topic: "Delivery Devices", questionType: "multiple-choice", examTip: "NRB: reservoir 600-1000 mL, delivers 60-80% FiO2 at 10-15 L/min. NOT 100%. Bag stays ≥ 1/3 full." },
  { id: "rrt-aw-024", stem: "What is the difference between a fenestrated and non-fenestrated tracheostomy tube?", options: ["Fenestrated has an opening in the outer cannula allowing air to pass to the upper airway for speech", "Fenestrated is used only in emergencies", "Non-fenestrated is only for pediatric patients", "There is no clinical difference"], correctIndex: 0, rationale: "A fenestrated tracheostomy tube has an opening (fenestration) in the posterior wall of the outer cannula. When the inner cannula is removed and the cuff deflated, air can pass through the fenestration to the upper airway, enabling speech and more natural breathing. Use with a speaking valve. Non-fenestrated tubes have no opening and are used when a sealed system is needed.", difficulty: 2, category: "Airway Management", topic: "Tracheostomy Care", questionType: "multiple-choice", examTip: "Fenestrated trach: opening for speech (cuff deflated + inner cannula removed). Non-fenestrated: sealed system." },
  { id: "rrt-cc-024", stem: "What is the goal of the lung-protective ventilation strategy per ARDSNet?", options: ["Vt 4-6 mL/kg IBW, Pplat < 30 cmH2O, pH > 7.20, use PEEP/FiO2 table for PEEP titration", "Vt 10-12 mL/kg, Pplat < 45 cmH2O, normalize PaCO2", "No specific targets — use clinical judgment", "High Vt with high PEEP for maximum recruitment"], correctIndex: 0, rationale: "ARDSNet protocol: (1) Vt 4-6 mL/kg IBW, (2) Pplat < 30 cmH2O, (3) RR up to 35 to maintain pH > 7.20, (4) Use PEEP/FiO2 table (low or high PEEP strategy), (5) Target PaO2 55-80 or SpO2 88-95%, (6) Permissive hypercapnia acceptable if pH > 7.20. This is the single most evidence-based intervention in ARDS management.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "ARDS Management", questionType: "multiple-choice", examTip: "ARDSNet: Vt 4-6 mL/kg IBW, Pplat < 30, pH > 7.20, PEEP/FiO2 table. Know the protocol cold." },
  { id: "rrt-neo-025", stem: "What is the recommended compression-to-ventilation ratio for neonatal CPR?", options: ["3:1 ratio (3 compressions followed by 1 ventilation)", "30:2 ratio as in adult CPR", "15:2 ratio as in pediatric two-rescuer CPR", "Compressions only — no ventilations"], correctIndex: 0, rationale: "Neonatal CPR uses a unique 3:1 compression-to-ventilation ratio (3 compressions + 1 ventilation = 1 cycle; approximately 120 events/min = 90 compressions + 30 ventilations per minute). This differs from pediatric (15:2 two-rescuer) and adult (30:2) ratios. The two-thumb encircling technique is preferred for chest compressions in neonates.", difficulty: 2, category: "Neonatal & Pediatric Respiratory Care", topic: "Neonatal Resuscitation", questionType: "multiple-choice", examTip: "Neonatal CPR: 3:1 ratio (90 compressions + 30 ventilations/min). Two-thumb technique. Unique to neonates." },
  { id: "rrt-cp-023", stem: "What is the Frank-Starling mechanism?", options: ["Increased ventricular preload (end-diastolic volume) increases stroke volume up to an optimal point, beyond which further stretching decreases output", "Heart rate determines cardiac output regardless of preload", "Afterload is the sole determinant of cardiac output", "Blood pressure controls stroke volume"], correctIndex: 0, rationale: "The Frank-Starling mechanism states that increased ventricular end-diastolic volume (preload) stretches cardiac muscle fibers, generating stronger contractions and greater stroke volume — up to an optimal point. Beyond this point (excessive preload), the muscle is overstretched and contractile force decreases (descending limb = heart failure). This is the physiologic basis for fluid resuscitation.", difficulty: 3, category: "Cardiopulmonary Physiology", topic: "Pulmonary Circulation", questionType: "multiple-choice", examTip: "Frank-Starling: more preload → more stretch → stronger contraction → more SV. Until overstretched = failure." },
  { id: "rrt-aer-019", stem: "What is the difference between a pMDI and a breath-actuated MDI?", options: ["Breath-actuated MDI releases medication automatically when the patient inhales, eliminating hand-breath coordination", "pMDI is more effective than breath-actuated", "Breath-actuated requires a spacer; pMDI does not", "There is no difference"], correctIndex: 0, rationale: "A standard pMDI (press-and-breathe) requires coordination between canister actuation and inhalation. A breath-actuated MDI (e.g., Autohaler, Easi-Breathe) uses a spring mechanism that is triggered by inspiratory flow, releasing the dose automatically. This eliminates the coordination problem that causes poor technique in up to 70% of patients using standard pMDIs.", difficulty: 2, category: "Aerosol & Medication Delivery", topic: "Metered-Dose Inhalers", questionType: "multiple-choice", examTip: "Breath-actuated MDI: auto-triggers on inspiration. Solves hand-breath coordination problem." },
  { id: "rrt-sniv-017", stem: "What is the difference between central and obstructive sleep apnea?", options: ["Central: absent respiratory effort and airflow. Obstructive: respiratory effort present but airflow blocked by upper airway collapse", "They are the same condition", "Central only occurs during REM sleep", "Obstructive is caused by brain lesions"], correctIndex: 0, rationale: "Central sleep apnea (CSA): absent respiratory effort AND absent airflow — the brain fails to signal respiratory muscles. Causes: heart failure (CSR), stroke, opioids, high altitude. Obstructive sleep apnea (OSA): respiratory EFFORT is present but airflow is absent/reduced due to upper airway collapse. Many patients have mixed apnea (both components). Treatment differs significantly.", difficulty: 2, category: "Sleep & Noninvasive Ventilation", topic: "CPAP Titration", questionType: "multiple-choice", examTip: "Central: no effort, no flow (brain problem). Obstructive: effort present, no flow (airway collapse). Different treatments." },
  { id: "rrt-em-022", stem: "What medications are used in the ACLS tachycardia algorithm for stable monomorphic ventricular tachycardia?", options: ["Amiodarone 150 mg IV over 10 minutes or procainamide 20-50 mg/min", "Adenosine 6 mg rapid IV push", "Atropine 1 mg IV", "Magnesium 2 g IV push"], correctIndex: 0, rationale: "For stable monomorphic VT: amiodarone 150 mg IV over 10 minutes (may repeat) or procainamide (20-50 mg/min until arrhythmia suppressed, hypotension, QRS widens > 50%, or max 17 mg/kg). For unstable VT with pulse: synchronized cardioversion. Adenosine is for SVT. Atropine is for bradycardia. Magnesium is for torsades de pointes.", difficulty: 3, category: "Emergency Respiratory Care", topic: "CPR/ACLS Protocols", questionType: "multiple-choice", examTip: "Stable monomorphic VT: amiodarone 150 mg IV or procainamide. Unstable: cardiovert. Torsades: magnesium." },
  { id: "rrt-pa-019", stem: "What does a chest X-ray showing 'Kerley B lines' indicate?", options: ["Interstitial pulmonary edema from elevated left heart pressures (CHF)", "Pneumothorax", "Pleural thickening", "Normal finding in elderly patients"], correctIndex: 0, rationale: "Kerley B lines are thin horizontal lines (1-2 cm) at the lung periphery/bases on CXR, representing thickened interlobular septa from interstitial edema. They are an early sign of congestive heart failure before frank alveolar edema develops. Other CHF CXR findings: cardiomegaly, cephalization, bilateral pleural effusions, bat-wing pattern (alveolar edema).", difficulty: 3, category: "Patient Assessment", topic: "Chest X-Ray Interpretation", questionType: "multiple-choice", examTip: "Kerley B lines: horizontal peripheral lines = interstitial edema (early CHF). With cephalization and cardiomegaly." },
  { id: "rrt-ic-018", stem: "What is the proper sequence for cleaning reusable respiratory equipment?", options: ["Disassemble, pre-clean (remove organic material), clean (detergent wash), rinse, disinfect/sterilize, dry, package", "Rinse with water only", "Disinfect without cleaning first", "Sterilize without disassembly"], correctIndex: 0, rationale: "Proper equipment reprocessing sequence: (1) Disassemble into component parts, (2) Pre-clean (remove gross organic material at point of use), (3) Clean with enzymatic detergent and scrub, (4) Rinse thoroughly, (5) Disinfect or sterilize based on Spaulding classification, (6) Dry completely (moisture promotes microbial growth), (7) Package and store properly. Cleaning before disinfection is essential — organic material inactivates disinfectants.", difficulty: 2, category: "Infection Control & Equipment", topic: "Equipment Disinfection", questionType: "multiple-choice", examTip: "Equipment reprocessing: disassemble → pre-clean → clean → rinse → disinfect/sterilize → dry → package." },
  { id: "rrt-mv-052", stem: "What is the recommended approach for a patient who fails an SBT?", options: ["Return to comfortable ventilator settings, identify and address the cause of failure, retry SBT in 24 hours", "Immediately proceed with extubation despite failure", "Perform tracheostomy", "Increase sedation and do not reattempt weaning"], correctIndex: 0, rationale: "After SBT failure: (1) Return to pre-SBT comfortable ventilator settings, (2) Identify the cause (cardiac, respiratory, neurological, metabolic, psychological), (3) Address reversible causes (diuresis, pain control, nutrition, mobility, resolve infection), (4) Consider daily SAT + SBT protocol, (5) Retry SBT in 24 hours. If prolonged failure (> 7 days of weaning attempts), consider progressive weaning protocols or tracheostomy.", difficulty: 3, category: "Mechanical Ventilation", topic: "Weaning Protocols", questionType: "multiple-choice", examTip: "Failed SBT: return to comfort, find the cause, address it, retry in 24 hours. Don't give up after one failure." },
  { id: "rrt-abg-035", stem: "A patient with salicylate (aspirin) overdose has ABG: pH 7.45, PaCO2 18, HCO3 12. What mixed disorder is present?", options: ["Mixed respiratory alkalosis AND metabolic acidosis — salicylate stimulates both respiratory center and causes metabolic acidosis", "Pure respiratory alkalosis", "Pure metabolic acidosis", "Normal acid-base balance"], correctIndex: 0, rationale: "Salicylate overdose causes a characteristic mixed disorder: (1) Respiratory alkalosis from direct stimulation of the medullary respiratory center (PaCO2 18), AND (2) Metabolic acidosis from salicylic acid accumulation, uncoupled oxidative phosphorylation, and lactic acidosis (HCO3 12). The pH may be normal, alkalotic, or acidotic depending on which process dominates.", difficulty: 5, category: "ABG Interpretation", topic: "Mixed Acid-Base Disorders", questionType: "case-based", examTip: "Salicylate OD: classic MIXED disorder — respiratory alkalosis + metabolic acidosis. pH variable." },
  { id: "rrt-neo-026", stem: "What are the signs of respiratory distress syndrome (RDS) in a preterm neonate?", options: ["Tachypnea, grunting, nasal flaring, subcostal/intercostal retractions, and cyanosis within hours of birth", "Productive cough and fever", "Absent cry at birth", "Normal respiratory pattern with isolated cyanosis"], correctIndex: 0, rationale: "Neonatal RDS (hyaline membrane disease) presents within 2-4 hours of birth in preterm neonates (surfactant deficiency): tachypnea (RR > 60), grunting (creates auto-PEEP to prevent alveolar collapse), nasal flaring, retractions (subcostal, intercostal, suprasternal), and cyanosis. CXR shows diffuse ground-glass opacity with air bronchograms. Treatment: surfactant + CPAP/ventilation.", difficulty: 2, category: "Neonatal & Pediatric Respiratory Care", topic: "Surfactant Therapy", questionType: "case-based", examTip: "RDS: preterm + tachypnea + grunting + retractions + ground-glass CXR within hours of birth. Treat with surfactant." },
  { id: "rrt-cc-025", stem: "What hemodynamic values would you expect in a patient with hypovolemic shock?", options: ["Low CVP, low PAWP, low CO, high SVR, low SvO2", "High CVP, high PAWP, low CO", "Low CVP, high CO, low SVR", "Normal hemodynamics"], correctIndex: 0, rationale: "Hypovolemic shock hemodynamic profile: Low CVP (< 2-6 mmHg) from decreased venous return, low PAWP (< 8 mmHg) from decreased preload, low CO/CI from decreased filling, high SVR (> 1200 dynes·sec/cm5) from compensatory vasoconstriction, and low SvO2 (< 60%) from increased oxygen extraction. Treatment: aggressive fluid resuscitation.", difficulty: 3, category: "Critical Care Respiratory Therapy", topic: "Hemodynamic Monitoring", questionType: "multiple-choice", examTip: "Hypovolemic shock: everything LOW (CVP, PAWP, CO) except SVR (HIGH = compensatory vasoconstriction)." },
  { id: "rrt-cp-024", stem: "How is oxygen delivery (DO2) calculated?", options: ["DO2 = CO × CaO2 × 10 (normal approximately 1000 mL O2/min)", "DO2 = FiO2 × PaO2", "DO2 = Hb × SaO2", "DO2 = PaO2 / FiO2"], correctIndex: 0, rationale: "DO2 = CO × CaO2 × 10 = CO × [(1.34 × Hb × SaO2) + (0.003 × PaO2)] × 10. Normal DO2 ≈ 1000 mL O2/min (or 500-600 mL/min/m2 indexed). DO2 depends on cardiac output, hemoglobin, and oxygen saturation. Critically ill patients need DO2 > VO2 (normal VO2 ≈ 250 mL/min). The DO2/VO2 ratio should be > 4:1.", difficulty: 3, category: "Cardiopulmonary Physiology", topic: "Oxygen Transport", questionType: "multiple-choice", examTip: "DO2 = CO × CaO2 × 10. Normal ~1000 mL/min. Three determinants: CO, Hb, SaO2." },
  { id: "rrt-aer-020", stem: "What is the difference between albuterol and levalbuterol (Xopenex)?", options: ["Levalbuterol is the R-isomer of albuterol, producing bronchodilation with potentially fewer cardiac side effects", "They are completely different drug classes", "Albuterol is the R-isomer only", "Levalbuterol is an anticholinergic"], correctIndex: 0, rationale: "Albuterol is a racemic mixture of R- and S-isomers. Levalbuterol (Xopenex) contains only the R-isomer (the active bronchodilating component). The S-isomer may have pro-inflammatory effects and contribute to side effects (tachycardia, tremor). Clinical significance is debated — some studies show similar efficacy and side effect profiles. Levalbuterol costs more.", difficulty: 2, category: "Aerosol & Medication Delivery", topic: "Bronchodilator Therapy", questionType: "multiple-choice", examTip: "Levalbuterol = R-isomer only of albuterol. Theoretically fewer side effects. Clinical difference debated." },
  { id: "rrt-mv-053", stem: "What is the therapeutic role of inhaled nitric oxide (iNO) in mechanical ventilation?", options: ["Selective pulmonary vasodilator that improves oxygenation by improving V/Q matching in ventilated lung regions", "Systemic vasodilator that reduces blood pressure", "Bronchodilator for asthma", "Mucolytic agent"], correctIndex: 0, rationale: "iNO is a selective pulmonary vasodilator: it dilates pulmonary vessels ONLY in ventilated alveoli, redirecting blood flow to well-ventilated areas (improving V/Q matching). It does not cause systemic vasodilation (rapidly inactivated by hemoglobin). Used in: ARDS with refractory hypoxemia, PPHN (persistent pulmonary hypertension of the newborn), post-cardiac surgery. Typical dose: 5-40 ppm.", difficulty: 4, category: "Mechanical Ventilation", topic: "ARDS Ventilation Strategy", questionType: "multiple-choice", examTip: "iNO: selective pulmonary vasodilator. Improves V/Q in ventilated areas. No systemic effect. Used in ARDS, PPHN." },
  { id: "rrt-pa-020", stem: "What scoring system uses respiratory rate, oxygen saturation, supplemental oxygen use, temperature, systolic BP, heart rate, and level of consciousness?", options: ["NEWS (National Early Warning Score) — used for early detection of clinical deterioration", "APACHE II", "Glasgow Coma Scale", "SOFA score"], correctIndex: 0, rationale: "NEWS (National Early Warning Score) uses 7 parameters: RR, SpO2, supplemental O2, temperature, SBP, HR, and AVPU (level of consciousness). Each scored 0-3 (maximum 20). Score ≥ 5 = urgent clinical review. Score ≥ 7 = emergency response. NEWS is used to detect clinical deterioration early and trigger appropriate responses.", difficulty: 2, category: "Patient Assessment", topic: "Respiratory Physical Exam", questionType: "multiple-choice", examTip: "NEWS: 7 vital sign parameters. ≥ 5 = urgent review. ≥ 7 = emergency. Early warning system." },
  { id: "rrt-ic-019", stem: "What is high-level disinfection (HLD) and for which respiratory equipment is it required?", options: ["Destroys all microorganisms except high numbers of bacterial spores; required for semi-critical items like bronchoscopes and laryngoscope blades", "Same as sterilization", "Required only for non-critical items", "Low-level cleaning with soap and water"], correctIndex: 0, rationale: "HLD destroys bacteria, mycobacteria, fungi, and viruses but NOT high numbers of bacterial spores (sterilization kills spores). HLD is required for semi-critical items that contact mucous membranes: bronchoscopes, laryngoscope blades (reusable), nebulizer parts (reusable patient equipment). Methods: glutaraldehyde, OPA, hydrogen peroxide. Critical items (enter sterile tissue) require sterilization.", difficulty: 2, category: "Infection Control & Equipment", topic: "Equipment Disinfection", questionType: "multiple-choice", examTip: "HLD: kills everything except high-level spores. For semi-critical items (mucous membrane contact). Bronchoscopes, laryngoscopes." },
];
